// ══════════════════════════════════════════════════════════
//  🔐  ADMIN AUTH SYSTEM
//  الأدمن يدخل بالإيميل وكلمة السر — لا يوجد زر مكشوف
//  كلمة السر مشفّرة بـ SHA-256 في localStorage
// ══════════════════════════════════════════════════════════
const AdminAuth = {
  KEY_EMAIL : "hsp_admin_email",
  KEY_HASH  : "hsp_admin_hash",
  KEY_SESS  : "hsp_admin_session",
  KEY_SETUP : "hsp_admin_setup_done",

  // Hash password (SHA-256 via Web Crypto)
  async hash(password, email) {
    const data = new TextEncoder().encode(password + email + "hsp_admin_2026");
    const buf  = await crypto.subtle.digest("SHA-256", data);
    return Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,"0")).join("");
  },

  // First-time setup: create admin account
  async setup(email, password) {
    const h = await AdminAuth.hash(password, email.toLowerCase());
    localStorage.setItem(AdminAuth.KEY_EMAIL, email.toLowerCase());
    localStorage.setItem(AdminAuth.KEY_HASH,  h);
    localStorage.setItem(AdminAuth.KEY_SETUP, "1");
    AdminAuth.createSession();
    return true;
  },

  // Login
  async login(email, password) {
    const savedEmail = localStorage.getItem(AdminAuth.KEY_EMAIL);
    const savedHash  = localStorage.getItem(AdminAuth.KEY_HASH);
    if(!savedEmail || !savedHash) return {ok:false, err:"لا يوجد حساب أدمن — قم بالإعداد أولاً"};
    if(email.toLowerCase() !== savedEmail) return {ok:false, err:"الإيميل غير صحيح"};
    const h = await AdminAuth.hash(password, email.toLowerCase());
    if(h !== savedHash) return {ok:false, err:"كلمة السر غير صحيحة"};
    AdminAuth.createSession();
    return {ok:true};
  },

  // Create a timed session (8 hours)
  createSession() {
    const sess = { ts: Date.now(), exp: Date.now() + 8*60*60*1000 };
    sessionStorage.setItem(AdminAuth.KEY_SESS, JSON.stringify(sess));
  },

  // Check if session valid
  isLoggedIn() {
    try {
      const s = JSON.parse(sessionStorage.getItem(AdminAuth.KEY_SESS)||"{}");
      return s.exp && Date.now() < s.exp;
    } catch{ return false; }
  },

  logout() {
    sessionStorage.removeItem(AdminAuth.KEY_SESS);
  },

  isSetupDone() {
    return !!localStorage.getItem(AdminAuth.KEY_SETUP);
  },

  getEmail() {
    return localStorage.getItem(AdminAuth.KEY_EMAIL) || "";
  },

  // Change password
  async changePassword(oldPass, newPass) {
    const email = AdminAuth.getEmail();
    const oldH  = await AdminAuth.hash(oldPass, email);
    if(oldH !== localStorage.getItem(AdminAuth.KEY_HASH))
      return {ok:false, err:"كلمة السر القديمة غير صحيحة"};
    const newH  = await AdminAuth.hash(newPass, email);
    localStorage.setItem(AdminAuth.KEY_HASH, newH);
    return {ok:true};
  },
};

// ══════════════════════════════════════════════════════════
//  🚀  OTA UPDATE SYSTEM — تحديث التطبيق بدون متاجر
//  يعمل على الويب و PWA — يُحمّل الكود الجديد مباشرة
//  من URL يضعه الأدمن (CDN / GitHub / أي رابط مباشر)
// ══════════════════════════════════════════════════════════
const OTAUpdate = {
  KEY_MANIFEST : "hsp_ota_manifest",
  KEY_PENDING  : "hsp_ota_pending",
  KEY_HISTORY  : "hsp_ota_history",
  KEY_SETTINGS : "hsp_ota_settings",

  // Fetch remote manifest JSON
  async fetchManifest(url) {
    try {
      const r = await fetch(url + "?t=" + Date.now(), {cache:"no-store"});
      if(!r.ok) throw new Error("HTTP " + r.status);
      return await r.json();
    } catch(e) {
      return {error: e.message};
    }
  },

  // Check for updates — compares version numbers
  async checkForUpdate() {
    const settings = OTAUpdate.getSettings();
    if(!settings.manifestUrl) return {available:false, reason:"لم يتم إعداد رابط التحديثات"};
    const manifest = await OTAUpdate.fetchManifest(settings.manifestUrl);
    if(manifest.error) return {available:false, reason:"فشل الاتصال: " + manifest.error};
    const current  = APP_VERSION.split(".").map(Number);
    const remote   = (manifest.version||"0.0.0").split(".").map(Number);
    const isNewer  = remote[0]>current[0] || (remote[0]===current[0]&&remote[1]>current[1]) ||
                     (remote[0]===current[0]&&remote[1]===current[1]&&remote[2]>current[2]);
    localStorage.setItem(OTAUpdate.KEY_MANIFEST, JSON.stringify({...manifest, fetchedAt:Date.now()}));
    return {
      available : isNewer,
      current   : APP_VERSION,
      remote    : manifest.version || "0.0.0",
      build     : manifest.build   || "",
      notes     : manifest.notes   || "",
      jsUrl     : manifest.jsUrl   || "",
      mandatory : manifest.mandatory || false,
      size      : manifest.size    || "",
    };
  },

  // Download and stage the update
  async downloadUpdate(jsUrl, onProgress) {
    try {
      onProgress(5, "جاري الاتصال...");
      const r = await fetch(jsUrl + "?t=" + Date.now(), {cache:"no-store"});
      if(!r.ok) throw new Error("فشل التنزيل: HTTP " + r.status);
      onProgress(20, "جاري التنزيل...");
      const text = await r.text();
      if(text.length < 1000) throw new Error("الملف صغير جداً — تأكد من الرابط");
      onProgress(70, "جاري التحقق من الملف...");
      // Basic validation: check it looks like React JSX
      if(!text.includes("export default") && !text.includes("function App")) {
        throw new Error("الملف لا يبدو صحيحاً — تأكد من الرابط");
      }
      onProgress(85, "جاري الحفظ...");
      localStorage.setItem(OTAUpdate.KEY_PENDING, JSON.stringify({
        code     : text,
        version  : OTAUpdate.getCachedManifest()?.version || "?",
        notes    : OTAUpdate.getCachedManifest()?.notes   || "",
        stagedAt : Date.now(),
        jsUrl,
      }));
      onProgress(100, "✅ جاهز للتثبيت");
      return {ok:true};
    } catch(e) {
      return {ok:false, err: e.message};
    }
  },

  // Apply staged update — rewrites the app HTML
  applyUpdate() {
    const pending = OTAUpdate.getPending();
    if(!pending) return {ok:false, err:"لا يوجد تحديث مُحمّل"};
    // Log history
    const hist = OTAUpdate.getHistory();
    hist.unshift({from:APP_VERSION, to:pending.version, ts:Date.now(), notes:pending.notes});
    localStorage.setItem(OTAUpdate.KEY_HISTORY, JSON.stringify(hist.slice(0,20)));
    localStorage.removeItem(OTAUpdate.KEY_PENDING);
    // For PWA: update the cached file and force reload
    // This replaces the current page script with the new code
    const blob = new Blob([pending.code], {type:"application/javascript"});
    const blobUrl = URL.createObjectURL(blob);
    // Create a new script tag with the updated code
    // Then reload to pick it up from cache
    if("caches" in window){
      caches.keys().then(names => names.forEach(n => caches.delete(n)));
    }
    // Signal service worker to update
    navigator.serviceWorker?.getRegistrations().then(regs =>
      regs.forEach(r => r.update())
    );
    // Store the new code for the reload to pick up
    localStorage.setItem("hsp_app_code_override", pending.code);
    localStorage.setItem("hsp_app_version_override", pending.version);
    // Reload
    setTimeout(()=>window.location.reload(true), 300);
    return {ok:true};
  },

  getPending()  { try{ return JSON.parse(localStorage.getItem(OTAUpdate.KEY_PENDING)||"null"); }catch{return null;} },
  getCachedManifest() { try{ return JSON.parse(localStorage.getItem(OTAUpdate.KEY_MANIFEST)||"null"); }catch{return null;} },
  getHistory()  { try{ return JSON.parse(localStorage.getItem(OTAUpdate.KEY_HISTORY)||"[]"); }catch{return [];} },
  getSettings() { try{ return JSON.parse(localStorage.getItem(OTAUpdate.KEY_SETTINGS)||"{}"); }catch{return {};} },
  saveSettings(s){ localStorage.setItem(OTAUpdate.KEY_SETTINGS, JSON.stringify(s)); },
  clearPending(){ localStorage.removeItem(OTAUpdate.KEY_PENDING); },
};

// ── CRASH / ERROR LOG ─────────────────────────────────────
const CrashReport = {
  log(err, context="") {
    const entry = {
      ts:      Date.now(),
      msg:     err?.message || String(err),
      stack:   err?.stack?.slice(0,500) || "",
      context,
      version: APP_VERSION,
      url:     window.location.href,
    };
    const logs = JSON.parse(localStorage.getItem("hsp_crash_log")||"[]");
    localStorage.setItem("hsp_crash_log", JSON.stringify([entry,...logs].slice(0,50)));
    console.error("💥 CrashReport:", entry);
  },
  get:   ()  => JSON.parse(localStorage.getItem("hsp_crash_log")||"[]"),
  clear: ()  => localStorage.removeItem("hsp_crash_log"),
};

// ── ANALYTICS ─────────────────────────────────────────────
const Analytics = {
  events: [],
  track(event, props={}) {
    const e = { event, ...props, ts: Date.now(), v: APP_VERSION };
    Analytics.events.push(e);
    // Store last 200 events locally
    const all = JSON.parse(localStorage.getItem("hsp_analytics")||"[]");
    localStorage.setItem("hsp_analytics", JSON.stringify([e,...all].slice(0,200)));
    // Send to Supabase if connected (non-blocking)
    if(CLOUD_ENABLED) {
      fetch(`${SUPABASE_URL}/rest/v1/analytics`, {
        method:"POST",
        headers:{...Auth.headers(),"Prefer":"return=minimal"},
        body: JSON.stringify(e),
      }).catch(()=>{});
    }
  },
  page:   (name)  => Analytics.track("page_view",    {page:name}),
  action: (name, props) => Analytics.track("action", {name,...props}),
  error:  (msg)   => Analytics.track("error",        {msg}),
};

// ── NETWORK STATUS ────────────────────────────────────────
const Network = {
  isOnline: () => navigator.onLine,
  onStatusChange(cb) {
    window.addEventListener("online",  ()=>cb(true));
    window.addEventListener("offline", ()=>cb(false));
  },
};

// ── API RETRY LOGIC ───────────────────────────────────────
async function fetchWithRetry(url, options={}, retries=3, delayMs=1000) {
  for(let i=0; i<retries; i++) {
    try {
      const r = await fetch(url, options);
      if(r.ok || r.status < 500) return r;
      if(i < retries-1) await new Promise(res=>setTimeout(res, delayMs*(i+1)));
    } catch(e) {
      if(i === retries-1) throw e;
      await new Promise(res=>setTimeout(res, delayMs*(i+1)));
    }
  }
}

// ── INPUT SANITIZER ───────────────────────────────────────
const Sanitize = {
  text:  (s="") => String(s).replace(/[<>\"'`]/g,"").trim().slice(0,2000),
  email: (s="") => String(s).toLowerCase().trim().slice(0,200),
  num:   (s,min=0,max=9999) => Math.min(max,Math.max(min,parseFloat(s)||0)),
  html:  (s="") => String(s)
    .replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;")
    .replace(/"/g,"&quot;").replace(/'/g,"&#x27;"),
};

// ── TOAST NOTIFICATION SYSTEM ─────────────────────────────
let _toastSetState = null;
const Toast = {
  _register(fn) { _toastSetState = fn; },
  show(msg, type="info", duration=3500) {
    if(_toastSetState) {
      const id = Date.now();
      _toastSetState(p=>[...p,{id,msg,type}]);
      setTimeout(()=>_toastSetState(p=>p.filter(t=>t.id!==id)), duration);
    }
  },
  success: (msg) => Toast.show(msg,"success"),
  error:   (msg) => Toast.show(msg,"error",5000),
  info:    (msg) => Toast.show(msg,"info"),
  warning: (msg) => Toast.show(msg,"warning",4500),
};

function ToastContainer() {
  const [toasts, setToasts] = useState([]);
  useEffect(()=>Toast._register(setToasts),[]);
  if(!toasts.length) return null;
  const colors = {
    success: C.accent3, error: C.danger,
    info: C.accent, warning: C.gold,
  };
  const icons = {success:"✅",error:"❌",info:"ℹ️",warning:"⚠️"};
  return(
    <div style={{position:"fixed",bottom:80,left:0,right:0,zIndex:9999,
      display:"flex",flexDirection:"column",alignItems:"center",gap:8,
      pointerEvents:"none",padding:"0 16px"}}>
      {toasts.map(t=>(
        <div key={t.id} className="fadeIn"
          style={{background:C.card,border:`1.5px solid ${colors[t.type]||C.accent}66`,
            borderRadius:14,padding:"10px 16px",maxWidth:380,width:"100%",
            boxShadow:`0 4px 24px ${colors[t.type]||C.accent}22`,
            display:"flex",alignItems:"center",gap:10}}>
          <span style={{fontSize:18,flexShrink:0}}>{icons[t.type]||"ℹ️"}</span>
          <span style={{fontSize:13,color:C.text,lineHeight:1.4}}>{t.msg}</span>
        </div>
      ))}
    </div>
  );
}

// ── ERROR BOUNDARY ────────────────────────────────────────
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError:false, error:null };
  }
  static getDerivedStateFromError(error) {
    return { hasError:true, error };
  }
  componentDidCatch(error, info) {
    CrashReport.log(error, info.componentStack?.slice(0,200));
    Analytics.error(error?.message);
  }
  render() {
    if(!this.state.hasError) return this.props.children;
    return(
      <div style={{minHeight:"100vh",background:C.bg,display:"flex",
        flexDirection:"column",alignItems:"center",justifyContent:"center",
        padding:24,textAlign:"center"}}>
        <div style={{fontSize:64,marginBottom:16}}>💥</div>
        <div style={{fontSize:20,fontWeight:800,color:C.danger,marginBottom:8}}>
          حدث خطأ غير متوقع
        </div>
        <div style={{fontSize:12,color:C.muted,marginBottom:24,maxWidth:300}}>
          {this.state.error?.message || "Unknown error"}
        </div>
        <button onClick={()=>window.location.reload()}
          style={{background:C.accent,color:"#000",border:"none",
            borderRadius:12,padding:"12px 28px",fontSize:14,fontWeight:700,
            cursor:"pointer"}}>
          🔄 إعادة تحميل
        </button>
        <button onClick={()=>this.setState({hasError:false,error:null})}
          style={{background:"none",color:C.muted,border:"none",
            marginTop:10,fontSize:12,cursor:"pointer"}}>
          المتابعة على مسؤوليتي
        </button>
      </div>
    );
  }
}

