// ── PWA INSTALL PROMPT ────────────────────────────────────
let _deferredPrompt = null;
window.addEventListener("beforeinstallprompt", e => {
  e.preventDefault();
  _deferredPrompt = e;
});

function PWAInstallBanner({onDismiss}) {
  const [show, setShow] = useState(false);
  useEffect(()=>{
    const dismissed = localStorage.getItem("hsp_pwa_dismissed");
    if(!dismissed && _deferredPrompt) {
      setTimeout(()=>setShow(true), 3000);
    }
  },[]);
  if(!show) return null;
  const install = async () => {
    if(!_deferredPrompt) return;
    _deferredPrompt.prompt();
    const { outcome } = await _deferredPrompt.userChoice;
    if(outcome==="accepted") {
      Analytics.track("pwa_installed");
      Toast.success("✅ تم تثبيت التطبيق!");
    }
    _deferredPrompt = null;
    setShow(false);
  };
  const dismiss = () => {
    localStorage.setItem("hsp_pwa_dismissed","1");
    setShow(false);
    onDismiss?.();
  };
  return(
    <div className="fadeIn" style={{position:"fixed",bottom:70,left:12,right:12,
      zIndex:9000,background:`linear-gradient(135deg,${C.card},${C.card2})`,
      border:`1.5px solid ${C.accent}44`,borderRadius:16,padding:"14px 16px",
      boxShadow:`0 8px 32px rgba(0,0,0,.4)`}}>
      <div style={{display:"flex",alignItems:"center",gap:12}}>
        <img src={APP_ICON} alt="" style={{width:44,height:44,borderRadius:10}}/>
        <div style={{flex:1}}>
          <div style={{fontWeight:800,fontSize:13}}>📲 ثبّت HealthSphere</div>
          <div style={{fontSize:11,color:C.muted,marginTop:2}}>
            يعمل بدون متجر — مثل تطبيق أصلي
          </div>
        </div>
        <button onClick={dismiss}
          style={{background:"none",color:C.muted,fontSize:18,border:"none",cursor:"pointer",
            padding:4}}>✕</button>
      </div>
      <button onClick={install}
        style={{width:"100%",marginTop:10,background:`linear-gradient(135deg,${C.accent},${C.accent2})`,
          color:"#000",border:"none",borderRadius:10,padding:"10px",
          fontSize:13,fontWeight:800,cursor:"pointer"}}>
        + إضافة للشاشة الرئيسية
      </button>
    </div>
  );
}

// ── ONBOARDING ────────────────────────────────────────────
function OnboardingFlow({onDone}) {
  const [step,setStep]=useState(0);
  const steps=[
    {icon:"🧠",title:"CBG — ذكاء طبي موحد",sub:"Claude + GPT-4 + BioGPT مع RAG من PubMed",color:C.accent},
    {icon:"🔬",title:"39 تحليلاً صحياً",sub:"تحليل صورة الجسم، الأعراض، الأدوية، والمزيد",color:C.accent2},
    {icon:"💳",title:"ابدأ مجاناً",sub:"3 تحليلات يومية مجانية + 50 كريدت عند التسجيل",color:C.accent3},
    {icon:"🔒",title:"بياناتك آمنة",sub:"مشفرة في Supabase · لا مشاركة مع أطراف ثالثة",color:C.gold},
  ];
  const s=steps[step];
  return(
    <div style={{position:"fixed",inset:0,background:C.bg,zIndex:8000,
      display:"flex",flexDirection:"column",alignItems:"center",
      justifyContent:"center",padding:28}}>
      {/* Progress dots */}
      <div style={{display:"flex",gap:6,marginBottom:40}}>
        {steps.map((_,i)=>(
          <div key={i} style={{width:i===step?24:8,height:8,borderRadius:4,
            background:i===step?s.color:C.border,transition:"all .3s"}}/>
        ))}
      </div>
      <div className="fadeIn" key={step}
        style={{textAlign:"center",maxWidth:320}}>
        <div style={{fontSize:72,marginBottom:20,
          filter:`drop-shadow(0 0 24px ${s.color}66)`}}>{s.icon}</div>
        <div style={{fontSize:22,fontWeight:900,marginBottom:10}}>{s.title}</div>
        <div style={{fontSize:14,color:C.muted,lineHeight:1.7}}>{s.sub}</div>
      </div>
      <div style={{marginTop:48,width:"100%",maxWidth:320}}>
        {step<steps.length-1 ? (
          <button onClick={()=>setStep(p=>p+1)}
            style={{width:"100%",background:`linear-gradient(135deg,${s.color},${s.color}aa)`,
              color:"#000",border:"none",borderRadius:14,padding:"14px",
              fontSize:15,fontWeight:800,cursor:"pointer"}}>
            التالي ←
          </button>
        ) : (
          <button onClick={()=>{
            localStorage.setItem("hsp_onboarded","1");
            Analytics.track("onboarding_complete");
            onDone();
          }}
            style={{width:"100%",background:`linear-gradient(135deg,${C.accent3},${C.accent})`,
              color:"#000",border:"none",borderRadius:14,padding:"14px",
              fontSize:15,fontWeight:800,cursor:"pointer"}}>
            ابدأ الآن 🚀
          </button>
        )}
        <button onClick={()=>{
          localStorage.setItem("hsp_onboarded","1");
          onDone();
        }}
          style={{width:"100%",marginTop:10,background:"none",
            color:C.muted,border:"none",fontSize:12,cursor:"pointer"}}>
          تخطي
        </button>
      </div>
    </div>
  );
}

