// T() — main translation function
function T(key, lang){
  const l = lang || AppLang.get();
  return (TRANS[key] && TRANS[key][l]) || (TRANS[key] && TRANS[key]["ar"]) || key;
}

// useLang hook — returns [lang, setLang, T, isAr]
function useLang(){
  const [lang, setLangState] = useState(AppLang.get);
  const setLang = (l) => { AppLang.set(l); setLangState(l); };
  const t = (key) => T(key, lang);
  return [lang, setLang, t, lang==="ar"];
}

