// ══════════════════════════════════════════════════
//  ☁️  SUPABASE CONFIG
//  1. افتح supabase.com → New Project
//  2. Settings → API → انسخ URL و anon key
// ══════════════════════════════════════════════════
const SUPABASE_URL  = localStorage.getItem("hsp_sb_url")  || "https://YOUR_PROJECT.supabase.co";
const SUPABASE_KEY  = localStorage.getItem("hsp_sb_key")  || "YOUR_ANON_KEY";
const CLOUD_ENABLED = SUPABASE_URL.includes("supabase.co") && !SUPABASE_URL.includes("YOUR_PROJECT");

// ── JWT token manager ──────────────────────────────
const Auth = {
  getToken:  ()  => sessionStorage.getItem("hsp_jwt") || "",
  setToken:  (t) => sessionStorage.setItem("hsp_jwt", t),
  clearToken:()  => sessionStorage.removeItem("hsp_jwt"),
  // Refresh token (long-lived)
  getRefresh:  ()  => localStorage.getItem("hsp_refresh") || "",
  setRefresh:  (t) => localStorage.setItem("hsp_refresh", t),
  clearRefresh:()  => localStorage.removeItem("hsp_refresh"),

  // Auto-refresh token before expiry
  async ensureFresh() {
    if(!CLOUD_ENABLED) return false;
    const refresh = Auth.getRefresh();
    if(!refresh) return false;
    try {
      const r = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=refresh_token`, {
        method:"POST",
        headers:{"Content-Type":"application/json","apikey":SUPABASE_KEY},
        body: JSON.stringify({ refresh_token: refresh }),
      });
      const d = await r.json();
      if(d.access_token) {
        Auth.setToken(d.access_token);
        if(d.refresh_token) Auth.setRefresh(d.refresh_token);
        return true;
      }
    } catch {}
    return false;
  },

  // Get auth headers (uses JWT when available)
  headers() {
    const token = Auth.getToken();
    return {
      "Content-Type":  "application/json",
      "apikey":        SUPABASE_KEY,
      "Authorization": token ? `Bearer ${token}` : `Bearer ${SUPABASE_KEY}`,
    };
  },
};

// ── Supabase REST + Auth client ───────────────────
const SB = {
  // ── REST helpers (use JWT when available) ──────
  async get(table, match={}) {
    if(!CLOUD_ENABLED) return null;
    try {
      const q = Object.entries(match).map(([k,v])=>`${k}=eq.${encodeURIComponent(v)}`).join("&");
      const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}?${q}&limit=1`,
        { headers:{...Auth.headers(),"Prefer":"return=representation"} });
      if(r.status===401){ await Auth.ensureFresh(); return null; }
      const d = await r.json();
      return Array.isArray(d) ? d[0] : null;
    } catch { return null; }
  },

  async upsert(table, data) {
    if(!CLOUD_ENABLED) return null;
    try {
      const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
        method:"POST",
        headers:{...Auth.headers(),"Prefer":"resolution=merge-duplicates,return=representation"},
        body: JSON.stringify(data),
      });
      if(r.status===401){ await Auth.ensureFresh(); return null; }
      const d = await r.json();
      return Array.isArray(d) ? d[0] : d;
    } catch { return null; }
  },

  async list(table, match={}, order="created_at", limit=200) {
    if(!CLOUD_ENABLED) return [];
    try {
      const q = Object.entries(match).map(([k,v])=>`${k}=eq.${encodeURIComponent(v)}`).join("&");
      const r = await fetch(
        `${SUPABASE_URL}/rest/v1/${table}?${q}&order=${order}.desc&limit=${limit}`,
        { headers: Auth.headers() }
      );
      const d = await r.json();
      return Array.isArray(d) ? d : [];
    } catch { return []; }
  },

  async delete(table, match={}) {
    if(!CLOUD_ENABLED) return;
    try {
      const q = Object.entries(match).map(([k,v])=>`${k}=eq.${encodeURIComponent(v)}`).join("&");
      await fetch(`${SUPABASE_URL}/rest/v1/${table}?${q}`,
        { method:"DELETE", headers: Auth.headers() });
    } catch {}
  },

  async update(table, match={}, data={}) {
    if(!CLOUD_ENABLED) return null;
    try {
      const q = Object.entries(match).map(([k,v])=>`${k}=eq.${encodeURIComponent(v)}`).join("&");
      const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}?${q}`, {
        method:"PATCH",
        headers:{...Auth.headers(),"Prefer":"return=representation"},
        body: JSON.stringify(data),
      });
      const d = await r.json();
      return Array.isArray(d) ? d[0] : d;
    } catch { return null; }
  },

  // ── Auth ───────────────────────────────────────
  async signUp(email, password, meta={}) {
    try {
      const r = await fetch(`${SUPABASE_URL}/auth/v1/signup`, {
        method:"POST",
        headers:{"Content-Type":"application/json","apikey":SUPABASE_KEY},
        body: JSON.stringify({ email, password, data: meta }),
      });
      const d = await r.json();
      if(d.access_token) {
        Auth.setToken(d.access_token);
        if(d.refresh_token) Auth.setRefresh(d.refresh_token);
      }
      return d;
    } catch { return null; }
  },

  async signIn(email, password) {
    try {
      const r = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
        method:"POST",
        headers:{"Content-Type":"application/json","apikey":SUPABASE_KEY},
        body: JSON.stringify({ email, password }),
      });
      const d = await r.json();
      if(d.access_token) {
        Auth.setToken(d.access_token);
        if(d.refresh_token) Auth.setRefresh(d.refresh_token);
      }
      return d;
    } catch { return null; }
  },

  async signOut() {
    try {
      await fetch(`${SUPABASE_URL}/auth/v1/logout`, {
        method:"POST",
        headers:{"Content-Type":"application/json","apikey":SUPABASE_KEY,
                 "Authorization":`Bearer ${Auth.getToken()}`},
      });
    } catch {}
    Auth.clearToken();
    Auth.clearRefresh();
  },

  async resetPassword(email) {
    try {
      await fetch(`${SUPABASE_URL}/auth/v1/recover`, {
        method:"POST",
        headers:{"Content-Type":"application/json","apikey":SUPABASE_KEY},
        body: JSON.stringify({ email }),
      });
    } catch {}
  },

  // ── Realtime-style polling for plan updates ────
  async getUserPlan(userId) {
    if(!CLOUD_ENABLED||!userId) return null;
    const p = await SB.get("profiles", {id:userId});
    return p?.plan || null;
  },
};

// ══════════════════════════════════════════════
//  💾 DB — Hybrid Storage (Local-First + Cloud)
//  كل write يُحفظ محلياً فوراً + يُزامَن للسحابة
// ══════════════════════════════════════════════
const DB = {
  // ── Local (instant, always works) ─────────────
  get: (k, d) => {
    try {
      const v = localStorage.getItem("hsp_"+k);
      return v != null ? JSON.parse(v) : d;
    } catch { return d; }
  },

  set: (k, v) => {
    try {
      localStorage.setItem("hsp_"+k, JSON.stringify(v));
      // Auto-sync to cloud for user data keys
      const userId = DB._currentUserId();
      if(userId && CLOUD_ENABLED && DB._syncKeys.includes(k)) {
        DB._debouncedSync(userId, k, v);
      }
    } catch {}
  },

  // Keys that get auto-synced to Supabase
  _syncKeys: [
    "user_profile","user_points","user_credits",
    "medications","appointments","notif_schedules",
    "anlys_hist","daily_usage","med_scans",
  ],

  // Get current user ID from session
  _currentUserId: () => {
    try {
      const s = JSON.parse(localStorage.getItem("hsp_auth_session") || "null");
      return s?.id || null;
    } catch { return null; }
  },

  // Debounce syncs to avoid too many writes (batch within 2 seconds)
  _syncTimers: {},
  _debouncedSync(userId, key, value) {
    clearTimeout(DB._syncTimers[key]);
    DB._syncTimers[key] = setTimeout(() => {
      SB.upsert("user_data", {
        user_id: userId,
        key,
        value: JSON.stringify(value),
        updated_at: new Date().toISOString(),
      }).catch(() => {}); // silent fail — local is source of truth
    }, 2000);
  },

  // ── Explicit sync methods ──────────────────────
  async syncUp(userId, key, value) {
    if(!CLOUD_ENABLED||!userId) return;
    DB.set(key, value);
    await SB.upsert("user_data", {
      user_id: userId, key,
      value: JSON.stringify(value),
      updated_at: new Date().toISOString(),
    });
  },

  async syncDown(userId, key, defaultVal) {
    const local = DB.get(key, defaultVal);
    if(!CLOUD_ENABLED||!userId) return local;
    try {
      const row = await SB.get("user_data", { user_id:userId, key });
      if(row?.value) {
        const parsed = JSON.parse(row.value);
        // Use newer version (compare updated_at if possible)
        DB.set(key, parsed);
        return parsed;
      }
    } catch {}
    return local;
  },

  // Full sync on login — pull all cloud data
  async fullSync(userId) {
    if(!CLOUD_ENABLED||!userId) return;
    try {
      const rows = await SB.list("user_data", { user_id:userId }, "updated_at");
      let count = 0;
      rows.forEach(r => {
        try {
          const parsed = JSON.parse(r.value);
          // Only update local if cloud version seems newer
          localStorage.setItem("hsp_"+r.key, JSON.stringify(parsed));
          count++;
        } catch {}
      });
      console.log(`☁️ Synced ${count} items from Supabase`);
    } catch(e) {
      console.warn("fullSync failed:", e);
    }
  },

  // Push all local data to cloud (first-time setup)
  async pushAll(userId) {
    if(!CLOUD_ENABLED||!userId) return;
    for(const key of DB._syncKeys) {
      const val = DB.get(key, null);
      if(val !== null) {
        await SB.upsert("user_data", {
          user_id: userId, key,
          value: JSON.stringify(val),
          updated_at: new Date().toISOString(),
        });
      }
    }
    console.log("☁️ All local data pushed to cloud");
  },

  cloudStatus: () => CLOUD_ENABLED ? "☁️ سحابي" : "💾 محلي فقط",
};
const uid = ()=>Math.random().toString(36).slice(2,9);
const fmt = d=>new Date(d).toLocaleString("ar-SA",{dateStyle:"short",timeStyle:"short"});
const fmtB = b=>b<1024?b+"B":b<1048576?(b/1024).toFixed(1)+"KB":(b/1048576).toFixed(1)+"MB";
const todayKey = ()=>new Date().toISOString().slice(0,10);

// ── POINTS ENGINE ─────────────────────────────
const Points = {
  get:()=>DB.get("user_points",{total:0,history:[],streak:0,lastLogin:"",lastStreakCheck:""}),
  save:(p)=>DB.set("user_points",p),

  // Called on every app open
  dailyLogin:(cfg)=>{
    if(!cfg.points?.enabled) return null;
    const p=Points.get();
    const today=todayKey();
    if(p.lastLogin===today) return null; // already claimed today

    const yesterday=new Date(Date.now()-86400000).toISOString().slice(0,10);
    const newStreak = p.lastLogin===yesterday ? (p.streak||0)+1 : 1;

    let bonus=0; let bonusMsg="";
    if(cfg.points.streakBonusEnabled){
      if(newStreak===3){bonus=cfg.points.streakBonus3Days||20;bonusMsg="🔥 3 أيام متتالية!";}
      else if(newStreak===7){bonus=cfg.points.streakBonus7Days||50;bonusMsg="⚡ أسبوع كامل!";}
      else if(newStreak===30){bonus=cfg.points.streakBonus30Days||200;bonusMsg="🏆 شهر كامل!";}
    }

    const earned=(cfg.points.dailyLoginPoints||10)+bonus;
    const updated={
      ...p, total:(p.total||0)+earned, streak:newStreak,
      lastLogin:today, lastStreakCheck:today,
      history:[{type:"login",pts:earned,msg:`دخول يومي${bonus?` + ${bonusMsg}`:""}`,ts:Date.now()},...(p.history||[])].slice(0,100),
    };
    Points.save(updated);
    return {earned,streak:newStreak,bonus,bonusMsg};
  },

  add:(type,cfg,custom=0)=>{
    if(!cfg.points?.enabled) return;
    const pts=custom||{analysis:cfg.points.analysisPoints||5,chat:cfg.points.chatPoints||2,scan:cfg.points.scanPoints||8}[type]||0;
    if(!pts) return;
    const p=Points.get();
    Points.save({...p,total:(p.total||0)+pts,
      history:[{type,pts,msg:{analysis:"تحليل صحي",chat:"رسالة دردشة",scan:"مسح طبي"}[type]||type,ts:Date.now()},...(p.history||[])].slice(0,100)});
  },

  spend:(pts)=>{
    const p=Points.get();
    if((p.total||0)<pts) return false;
    Points.save({...p,total:p.total-pts,
      history:[{type:"spend",pts:-pts,msg:"استخدام نقاط",ts:Date.now()},...(p.history||[])].slice(0,100)});
    return true;
  },
};

// ══════════════════════════════════════════════
//  💳 CREDITS ENGINE
// ══════════════════════════════════════════════
const Credits = {
  KEY: "hsp_user_credits",

  get: () => DB.get("user_credits", {
    balance: 0, totalEarned: 0, totalSpent: 0,
    transactions: [], lastDailyBonus: "",
  }),
  save: (d) => DB.set("user_credits", d),

  // Add credits
  add: (amount, reason="") => {
    const d = Credits.get();
    const updated = {
      ...d,
      balance: (d.balance||0) + amount,
      totalEarned: (d.totalEarned||0) + amount,
      transactions: [
        { type:"earn", amount, reason, ts: Date.now() },
        ...(d.transactions||[])
      ].slice(0, 200),
    };
    Credits.save(updated);
    return updated.balance;
  },

  // Spend credits — returns true if successful
  spend: (amount, reason="") => {
    const d = Credits.get();
    if((d.balance||0) < amount) return false;
    const updated = {
      ...d,
      balance: d.balance - amount,
      totalSpent: (d.totalSpent||0) + amount,
      transactions: [
        { type:"spend", amount: -amount, reason, ts: Date.now() },
        ...(d.transactions||[])
      ].slice(0, 200),
    };
    Credits.save(updated);
    return true;
  },

  // Check if user can afford
  canAfford: (amount) => (Credits.get().balance||0) >= amount,

  // Claim daily free credits
  claimDaily: (cfg) => {
    if(!cfg.credits?.enabled) return 0;
    const d = Credits.get();
    const today = todayKey();
    if(d.lastDailyBonus === today) return 0;
    const amount = cfg.credits.dailyFreeCredits || 10;
    Credits.save({ ...d, lastDailyBonus: today });
    Credits.add(amount, "كريدت يومي مجاني");
    return amount;
  },

  // Cost for action from config
  cost: (action, cfg) => cfg.credits?.costs?.[action] || 10,

  // Format balance display
  fmt: (n) => n >= 1000 ? (n/1000).toFixed(1)+"K" : String(n),
};

// ── DAILY USAGE TRACKER ──────────────────────
const Usage = {
  get:()=>{ const d=DB.get("daily_usage",{}); const t=todayKey(); return d[t]||{analyses:0,chats:0,scans:0,veins:0,skinvision:0}; },
  inc:(type)=>{
    const t=todayKey(); const all=DB.get("daily_usage",{});
    const day=all[t]||{analyses:0,chats:0,scans:0,veins:0,skinvision:0};
    day[type]=(day[type]||0)+1;
    // Keep only last 7 days
    const keys=Object.keys(all).sort().slice(-7);
    const cleaned=Object.fromEntries(keys.map(k=>[k,all[k]]));
    DB.set("daily_usage",{...cleaned,[t]:day});
  },
  canUse:(type,cfg,userPlan)=>{
    if(!cfg.freemium?.enabled) return {ok:true};
    // Check planFeatures for this plan
    const pf = (cfg.planFeatures||{})[userPlan||"free"] || {};
    const planLimit = pf[type]; // -1=unlimited, number=limit, undefined=use freemium defaults
    if(planLimit===-1) return {ok:true}; // unlimited for this plan
    if(userPlan && userPlan!=="free" && planLimit===undefined) return {ok:true};
    const u=Usage.get();
    const freemiumLimits={analyses:cfg.freemium.dailyFreeAnalyses||3,chats:cfg.freemium.dailyFreeChats||5,scans:cfg.freemium.dailyFreeMedScans||1,veins:cfg.freemium.freeVeinScans||2,skinvision:cfg.freemium.freeSkinVision||1};
    const limit = (planLimit!==undefined && planLimit>=0) ? planLimit : (freemiumLimits[type]||3);
    const used=u[type]||0;
    return {ok:used<limit, used, limit, remaining:Math.max(0,limit-used)};
  },

  // Check if a specific feature is enabled for a plan
  canUseFeature:(featureKey,cfg,userPlan)=>{
    // Global master switch first
    if(cfg.features && cfg.features[featureKey]===false) return false;
    // Plan-level feature access
    const pf = (cfg.planFeatures||{})[userPlan||"free"] || {};
    if(pf[featureKey]===false) return false;
    if(pf[featureKey]===true)  return true;
    // Default: free plan has limited access
    const FREE_BLOCKED = ["reports","api","hrDashboard","ssoEnabled","customDomain","resellerPortal","hl7","customAI"];
    if((userPlan||"free")==="free" && FREE_BLOCKED.includes(featureKey)) return false;
    return true;
  },
};

