// ── AI CALL ──────────────────────────────────
// ╔══════════════════════════════════════════════════════════════╗
// ║  🧠 CBG ENGINE v2 — Real Analytical Consensus + Fixed RAG   ║
// ╚══════════════════════════════════════════════════════════════╝

const CBG_CONFIG = {
  get CLAUDE_KEY()  {
    return DB.get("admin_cfg",{})?.apiKeys?.claudeKey ||
           DB.get("cbg_claude_key","") ||
           localStorage.getItem("hsp_claude_key") || "";
  },
  get GPT_KEY()     {
    return DB.get("admin_cfg",{})?.apiKeys?.openaiKey ||
           DB.get("cbg_gpt_key","") ||
           localStorage.getItem("hsp_openai_key") || "";
  },
  get BIOGPT_KEY()  {
    return DB.get("admin_cfg",{})?.apiKeys?.huggingfaceKey ||
           DB.get("cbg_biogpt_key","") ||
           localStorage.getItem("hsp_hf_key") || "";
  },
  get GEMINI_KEY()  {
    return DB.get("admin_cfg",{})?.apiKeys?.geminiKey ||
           localStorage.getItem("hsp_gemini_key") || "";
  },
  get CLAUDE_MODEL() {
    return DB.get("admin_cfg",{})?.apiKeys?.claudeModel || "claude-sonnet-4-20250514";
  },
  get GPT_MODEL() {
    return DB.get("admin_cfg",{})?.apiKeys?.openaiModel || "gpt-4o";
  },
  WEIGHTS: { claude: 0.45, gpt4: 0.35, biogpt: 0.20 },
  RAG_SOURCES: {
    pubmed:     { name:"PubMed",         icon:"🔬", enabled:true  },
    openfda:    { name:"OpenFDA",        icon:"💊", enabled:true  },
    clintrials: { name:"ClinicalTrials", icon:"🏥", enabled:true  },
    rxnorm:     { name:"RxNorm/NIH",     icon:"🧪", enabled:true  },
    umls:       { name:"UMLS",           icon:"📚", enabled:false },
  },
  CACHE: {},
  CACHE_TTL: 30 * 60 * 1000,
};

// ═══════════════════════════════════════════════
// 🔬 RAG ENGINE — Real APIs (Free & Authenticated)
// ═══════════════════════════════════════════════
const RAG = {

  // Cache helper
  cacheGet(key) {
    const c = CBG_CONFIG.CACHE[key];
    if(c && Date.now()-c.ts < CBG_CONFIG.CACHE_TTL) return c.data;
    return null;
  },
  cacheSet(key, data) { CBG_CONFIG.CACHE[key] = { data, ts:Date.now() }; },

  // PubMed — FREE official NCBI API
  async pubmed(query, max=3) {
    const ck = "pm_"+query;
    const cached = RAG.cacheGet(ck);
    if(cached) return cached;
    try {
      const q = encodeURIComponent(query);
      const sr = await fetch(
        `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi?db=pubmed&term=${q}&retmax=${max}&retmode=json`,
        { signal: AbortSignal.timeout(6000) }
      );
      const sd = await sr.json();
      const ids = sd?.esearchresult?.idlist || [];
      if(!ids.length) return [];
      const sumR = await fetch(
        `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esummary.fcgi?db=pubmed&id=${ids.join(",")}&retmode=json`,
        { signal: AbortSignal.timeout(6000) }
      );
      const sumD = await sumR.json();
      const result = ids.map(id => {
        const a = sumD?.result?.[id];
        return a ? {
          source:"PubMed", icon:"🔬", id,
          title: a.title?.replace(/<[^>]+>/g,"") || "",
          authors: (a.authors||[]).slice(0,2).map(x=>x.name).join(", "),
          journal: a.source || a.fulljournalname || "",
          year: (a.pubdate||"").slice(0,4),
          abstract: "",
          url: `https://pubmed.ncbi.nlm.nih.gov/${id}/`,
        } : null;
      }).filter(Boolean);
      RAG.cacheSet(ck, result);
      return result;
    } catch { return []; }
  },

  // OpenFDA — FREE official FDA drug database (replaces DrugBank)
  async openfda(query, max=2) {
    const ck = "fda_"+query;
    const cached = RAG.cacheGet(ck);
    if(cached) return cached;
    try {
      const q = encodeURIComponent(query);
      const r = await fetch(
        `https://api.fda.gov/drug/label.json?search=indications_and_usage:${q}+OR+description:${q}&limit=${max}`,
        { signal: AbortSignal.timeout(6000) }
      );
      const d = await r.json();
      const results = (d?.results||[]).map(item => ({
        source:"OpenFDA", icon:"💊",
        brand: item.openfda?.brand_name?.[0] || item.openfda?.generic_name?.[0] || query,
        generic: item.openfda?.generic_name?.[0] || "",
        manufacturer: item.openfda?.manufacturer_name?.[0] || "",
        indication: (item.indications_and_usage?.[0]||"").slice(0,300),
        warnings: (item.warnings?.[0]||"").slice(0,200),
        url: `https://labels.fda.gov/`,
      }));
      RAG.cacheSet(ck, results);
      return results;
    } catch { return []; }
  },

  // ClinicalTrials.gov — FREE official API v2
  async clinicalTrials(query, max=2) {
    const ck = "ct_"+query;
    const cached = RAG.cacheGet(ck);
    if(cached) return cached;
    try {
      const q = encodeURIComponent(query);
      const r = await fetch(
        `https://clinicaltrials.gov/api/v2/studies?query.term=${q}&pageSize=${max}&format=json`,
        { signal: AbortSignal.timeout(6000) }
      );
      const d = await r.json();
      const results = (d?.studies||[]).map(s => {
        const id   = s?.protocolSection?.identificationModule;
        const stat = s?.protocolSection?.statusModule;
        const des  = s?.protocolSection?.descriptionModule;
        const des2 = s?.protocolSection?.designModule;
        return {
          source:"ClinicalTrials", icon:"🏥",
          nctId: id?.nctId || "",
          title: id?.briefTitle || "",
          status: stat?.overallStatus || "",
          phase: des2?.phases?.[0] || "",
          summary: (des?.briefSummary||"").slice(0,250),
          url: `https://clinicaltrials.gov/study/${id?.nctId}`,
        };
      }).filter(t=>t.title);
      RAG.cacheSet(ck, results);
      return results;
    } catch { return []; }
  },

  // RxNorm — FREE NIH drug terminology API
  async rxnorm(drugName) {
    const ck = "rx_"+drugName;
    const cached = RAG.cacheGet(ck);
    if(cached) return cached;
    try {
      const q = encodeURIComponent(drugName);
      const r = await fetch(
        `https://rxnav.nlm.nih.gov/REST/drugs.json?name=${q}`,
        { signal: AbortSignal.timeout(5000) }
      );
      const d = await r.json();
      const groups = d?.drugGroup?.conceptGroup||[];
      const results = groups.flatMap(g=>
        (g.conceptProperties||[]).slice(0,2).map(p=>({
          source:"RxNorm", icon:"🧪",
          rxcui: p.rxcui,
          name: p.name,
          synonym: p.synonym||"",
          tty: p.tty,
          url: `https://mor.nlm.nih.gov/RxNav/search?searchBy=RXCUI&searchTerm=${p.rxcui}`,
        }))
      ).slice(0,3);
      RAG.cacheSet(ck, results);
      return results;
    } catch { return []; }
  },

  // Detect query intent
  getIntent(text) {
    if(/دواء|عقار|drug|medic|dose|mg|tablet|pill|capsule|جرعة/i.test(text))  return "drug";
    if(/تشخيص|أعراض|symptom|diagnos|مرض|disease/i.test(text))               return "diagnosis";
    if(/تجربة|بحث|trial|study|research|دراسة/i.test(text))                   return "research";
    if(/نتيجة|تحليل|تحاليل|lab|blood|فحص/i.test(text))                      return "lab";
    return "general";
  },

  // ── Master RAG fetch ──
  async fetchAll(query, intent) {
    const src = CBG_CONFIG.RAG_SOURCES;
    const results = { pubmed:[], openfda:[], clintrials:[], rxnorm:[] };
    const promises = [];

    if(src.pubmed.enabled)
      promises.push(RAG.pubmed(query).then(r=>{ results.pubmed=r; }));
    if(src.clintrials.enabled)
      promises.push(RAG.clinicalTrials(query).then(r=>{ results.clintrials=r; }));
    if(src.openfda.enabled && (intent==="drug"||intent==="diagnosis"))
      promises.push(RAG.openfda(query).then(r=>{ results.openfda=r; }));
    if(src.rxnorm.enabled && intent==="drug")
      promises.push(RAG.rxnorm(query).then(r=>{ results.rxnorm=r; }));

    await Promise.allSettled(promises);
    return results;
  },

  // Build compact context string for AI prompt
  formatContext(r) {
    const lines = [];
    if(r.pubmed?.length) {
      lines.push("📚 PubMed:");
      r.pubmed.forEach(a => lines.push(`  • [${a.year}] "${a.title}" — ${a.authors} (${a.journal}) → ${a.url}`));
    }
    if(r.clintrials?.length) {
      lines.push("🏥 ClinicalTrials:");
      r.clintrials.forEach(t => lines.push(`  • ${t.title} [${t.status}/${t.phase}] → ${t.url}`));
    }
    if(r.openfda?.length) {
      lines.push("💊 OpenFDA:");
      r.openfda.forEach(d => lines.push(`  • ${d.brand}/${d.generic} (${d.manufacturer}): ${d.indication}`));
    }
    if(r.rxnorm?.length) {
      lines.push("🧪 RxNorm:");
      r.rxnorm.forEach(x => lines.push(`  • ${x.name} [RXCUI:${x.rxcui}] → ${x.url}`));
    }
    return lines.join("\n");
  },

  // Build citation list for display
  buildCitations(r) {
    const cites = [];
    (r.pubmed||[]).forEach(a=>cites.push({ icon:"🔬", source:"PubMed",         text:`${a.title} (${a.year})`,    url:a.url }));
    (r.clintrials||[]).forEach(t=>cites.push({ icon:"🏥", source:"ClinicalTrials", text:`${t.title}`,              url:t.url }));
    (r.openfda||[]).forEach(d=>cites.push({ icon:"💊", source:"OpenFDA",        text:`${d.brand} — ${d.generic}`, url:d.url }));
    (r.rxnorm||[]).forEach(x=>cites.push({ icon:"🧪", source:"RxNorm",          text:x.name,                      url:x.url }));
    return cites;
  },
};

// ═══════════════════════════════════════════════
// 🤖 MODEL ADAPTERS
// ═══════════════════════════════════════════════
const MODELS = {

  async claude({ messages, system, maxTokens }) {
    const key = CBG_CONFIG.CLAUDE_KEY;
    if(!key) throw new Error("claude_no_key");
    const model = CBG_CONFIG.CLAUDE_MODEL;
    const r = await fetch("https://api.anthropic.com/v1/messages", {
      method:"POST",
      headers:{
        "Content-Type":"application/json",
        "x-api-key": key,
        "anthropic-version":"2023-06-01",
        "anthropic-dangerous-direct-browser-access":"true",
      },
      body: JSON.stringify({ model, max_tokens: maxTokens, system, messages }),
      signal: AbortSignal.timeout(30000),
    });
    if(!r.ok) throw new Error("Claude "+r.status);
    const d = await r.json();
    return d.content?.[0]?.text || "";
  },

  async gpt4({ messages, system, maxTokens }) {
    const key = CBG_CONFIG.GPT_KEY;
    if(!key) throw new Error("no_key");
    const model = CBG_CONFIG.GPT_MODEL;
    const msgs = [
      ...(system ? [{ role:"system", content:system }] : []),
      ...messages.map(m=>({
        role: m.role==="ai"?"assistant":m.role,
        content: Array.isArray(m.content)
          ? m.content.map(c=>c.type==="text"?c.text:c.type==="image"?"[image]":"").join(" ")
          : (m.content||""),
      })),
    ];
    const r = await fetch("https://api.openai.com/v1/chat/completions", {
      method:"POST",
      headers:{ "Content-Type":"application/json", "Authorization":`Bearer ${key}` },
      body: JSON.stringify({ model, max_tokens:maxTokens, messages: msgs }),
      signal: AbortSignal.timeout(30000),
    });
    if(!r.ok) throw new Error("GPT4 "+r.status);
    const d = await r.json();
    return d.choices?.[0]?.message?.content || "";
  },

  // BioGPT via HuggingFace Inference API — medical QA specialized
  async biogpt({ messages, system, maxTokens }) {
    const key = CBG_CONFIG.BIOGPT_KEY;
    if(!key) throw new Error("no_key");
    const last = messages[messages.length-1];
    const userText = Array.isArray(last?.content)
      ? last.content.find(c=>c.type==="text")?.text||""
      : (last?.content||"");
    const prompt = `${system ? "Context: "+system.slice(0,300)+"\n\n":""}Medical question: ${userText}\n\nEvidence-based answer:`;
    const r = await fetch(
      "https://api-inference.huggingface.co/models/microsoft/BioGPT-Large-PubMedQA",
      {
        method:"POST",
        headers:{ "Content-Type":"application/json", "Authorization":`Bearer ${key}` },
        body: JSON.stringify({
          inputs: prompt,
          parameters:{ max_new_tokens: Math.min(maxTokens, 400), do_sample:false, temperature:0.1 },
          options: { wait_for_model:true, use_cache:true },
        }),
        signal: AbortSignal.timeout(45000), // BioGPT needs more time
      }
    );
    if(!r.ok) throw new Error("BioGPT "+r.status);
    const d = await r.json();
    const raw = Array.isArray(d) ? d[0]?.generated_text||"" : d?.generated_text||"";
    return raw.split("Evidence-based answer:").pop()?.trim() || raw.slice(prompt.length).trim() || "";
  },
};

// ═══════════════════════════════════════════════
// 🧬 TRUE ANALYTICAL CONSENSUS ENGINE
// ═══════════════════════════════════════════════
const Consensus = {

  // Extract key medical claims from a response
  extractClaims(text) {
    if(!text) return [];
    const sentences = text
      .replace(/\n+/g," ")
      .split(/[.!?؟،]\s+/)
      .map(s=>s.trim())
      .filter(s=>s.length > 20);
    return sentences.slice(0,10);
  },

  // Calculate semantic similarity between two texts (Jaccard on medical words)
  similarity(a, b) {
    if(!a||!b) return 0;
    const tokenize = t => new Set(
      t.toLowerCase()
       .replace(/[^a-zأ-ي0-9\s]/g,"")
       .split(/\s+/)
       .filter(w=>w.length>3)
    );
    const sA = tokenize(a);
    const sB = tokenize(b);
    const intersection = [...sA].filter(w=>sB.has(w)).length;
    const union = new Set([...sA,...sB]).size;
    return union===0 ? 0 : intersection/union;
  },

  // Find points all models AGREE on
  findAgreements(responses) {
    const available = Object.entries(responses).filter(([,v])=>v&&v.length>10);
    if(available.length < 2) return [];
    const agreements = [];
    const claimsMap = Object.fromEntries(
      available.map(([k,v])=>[k, Consensus.extractClaims(v)])
    );
    const [firstKey, ...restKeys] = available.map(([k])=>k);
    const firstClaims = claimsMap[firstKey]||[];
    firstClaims.forEach(claim => {
      const matchCount = restKeys.filter(k =>
        (claimsMap[k]||[]).some(c2 => Consensus.similarity(claim,c2) > 0.22)
      ).length;
      if(matchCount >= restKeys.length * 0.5) {
        agreements.push(claim);
      }
    });
    return agreements.slice(0,4);
  },

  // Find points where models DISAGREE (interesting divergences)
  findDivergences(responses) {
    const available = Object.entries(responses).filter(([,v])=>v&&v.length>10);
    if(available.length < 2) return [];
    const divergences = [];
    const pairs = [];
    for(let i=0;i<available.length;i++)
      for(let j=i+1;j<available.length;j++)
        pairs.push([available[i],available[j]]);

    pairs.forEach(([[kA,vA],[kB,vB]]) => {
      const simScore = Consensus.similarity(vA,vB);
      if(simScore < 0.15) {
        divergences.push({
          models: [kA,kB],
          note: `${kA} و ${kB} يختلفان في التركيز`,
          scoreA: simScore,
        });
      }
    });
    return divergences.slice(0,2);
  },

  // Calculate confidence score for each model response
  scoreResponse(text, ragContext) {
    if(!text) return 0;
    let score = 0;
    // Length quality (not too short, not too long filler)
    const words = text.split(/\s+/).length;
    if(words>50)  score += 0.2;
    if(words>150) score += 0.1;
    // Has structure (lists, numbers, headers)
    if(/[•\-\*]|\d\.|#{1,3}/.test(text))    score += 0.15;
    // References RAG content
    if(ragContext && Consensus.similarity(text, ragContext) > 0.05) score += 0.2;
    // Medical specificity markers
    if(/mg|ml|dose|دواء|علاج|diagnosis|تشخيص|treatment|أعراض/i.test(text)) score += 0.15;
    // Has warnings/caveats (good medical practice)
    if(/تحذير|warning|⚠️|اعراض جانبية|side effect|استشر|consult/i.test(text)) score += 0.1;
    // Has uncertainty markers (good epistemic practice)
    if(/قد|ربما|possibly|may|might|احتمال/i.test(text)) score += 0.1;
    return Math.min(1, score);
  },

  // Build the final synthesized consensus response
  buildFinal(responses, ragContext, ragCitations) {
    const available = Object.entries(responses)
      .filter(([,v])=>v && v.length>10)
      .map(([k,v])=>({
        model: k,
        label: {claude:"Claude Sonnet",gpt4:"GPT-4o",biogpt:"BioGPT"}[k],
        icon:  {claude:"🔵",gpt4:"🟢",biogpt:"🟡"}[k],
        text: v,
        score: Consensus.scoreResponse(v, ragContext),
        weight: CBG_CONFIG.WEIGHTS[k]||0.33,
      }));

    if(available.length===0) throw new Error("All models failed");

    // Sort by weighted score
    available.sort((a,b)=>(b.score*b.weight)-(a.score*a.weight));

    // Find agreements and divergences
    const agreements  = Consensus.findAgreements(responses);
    const divergences = Consensus.findDivergences(responses);

    // Calculate overall consensus confidence
    const avgSim = available.length >= 2
      ? available.slice(1).reduce((acc,m)=>
          acc + Consensus.similarity(available[0].text, m.text), 0
        ) / (available.length-1)
      : 1;
    const confidenceLevel = avgSim > 0.35 ? "عالية 🟢"
                          : avgSim > 0.2  ? "متوسطة 🟡"
                          : "متباينة 🔴";

    // ── BUILD FINAL RESPONSE ──
    const lines = [];

    // Header
    lines.push(`🧠 **تحليل CBG الموحد** — ${available.map(m=>m.label).join(" + ")}`);
    lines.push(`📊 ثقة الإجماع: ${confidenceLevel} (${Math.round(avgSim*100)}% تطابق)`);
    lines.push("━".repeat(38));

    // Best model answer (highest weighted score) as primary
    lines.push("");
    lines.push("## 📋 التقييم الرئيسي");
    lines.push(available[0].text);

    // Agreements block
    if(agreements.length > 0) {
      lines.push("");
      lines.push("## ✅ نقاط الإجماع بين النماذج");
      agreements.forEach((a,i) => lines.push(`${i+1}. ${a}`));
    }

    // Secondary models — condensed
    if(available.length > 1) {
      lines.push("");
      lines.push("## 🔄 آراء النماذج الأخرى");
      available.slice(1).forEach(m => {
        lines.push(`**${m.icon} ${m.label}** (درجة: ${Math.round(m.score*100)}%):`);
        lines.push(m.text.slice(0,400) + (m.text.length>400?"...":""));
      });
    }

    // Divergences
    if(divergences.length > 0) {
      lines.push("");
      lines.push("## ⚖️ اختلافات ملحوظة بين النماذج");
      divergences.forEach(d => lines.push(`• ${d.note}`));
    }

    // RAG citations
    if(ragCitations?.length > 0) {
      lines.push("");
      lines.push("## 📖 المراجع العلمية (RAG)");
      ragCitations.slice(0,5).forEach(c =>
        lines.push(`${c.icon} **[${c.source}]** ${c.text}\n   → ${c.url}`)
      );
    }

    lines.push("");
    lines.push("─".repeat(38));
    lines.push("⚠️ *للأغراض المعلوماتية فقط — يُرجى استشارة طبيب متخصص*");

    return lines.join("\n");
  },
};

// ═══════════════════════════════════════════════
// 🚀 CBG MASTER ORCHESTRATOR
// ═══════════════════════════════════════════════
const CBG = {

  getAvailableModels() {
    const m = ["claude"];
    if(CBG_CONFIG.GPT_KEY)    m.push("gpt4");
    if(CBG_CONFIG.BIOGPT_KEY) m.push("biogpt");
    return m;
  },

  async call({ messages, system="", maxTokens=1000, useRAG=true, ragQuery="" }) {
    const lastMsg = messages[messages.length-1];
    const userText = Array.isArray(lastMsg?.content)
      ? lastMsg.content.find(c=>c.type==="text")?.text||""
      : (lastMsg?.content||"");
    const query  = ragQuery||userText;
    const intent = RAG.getIntent(query);

    // ── Step 1: RAG fetch (parallel) ──
    let ragContext = "", ragCitations = [], ragResults = null;
    if(useRAG && query.length > 4) {
      try {
        ragResults  = await RAG.fetchAll(query, intent);
        ragContext  = RAG.formatContext(ragResults);
        ragCitations = RAG.buildCitations(ragResults);
      } catch(e) { console.warn("RAG error:", e); }
    }

    // ── Step 2: Enriched system prompt ──
    const baseSystem = system || `أنت HealthSphere CBG — نموذج طبي موحد من Claude + BioGPT + GPT-4.
تخصصك: تقديم إجابات طبية دقيقة مبنية على الأدلة العلمية.
- أجب بنفس لغة المستخدم (عربي أو إنجليزي)
- استند للمراجع المقدمة من قاعدة البيانات الطبية RAG
- قدم إجابات منظمة بعناوين وأقسام
- لا تُشخّص قطعياً، بل وجّه وأرشد بالأدلة
- أضف تحذيراً: ⚠️ للأغراض المعلوماتية فقط`;

    const enrichedSystem = ragContext
      ? `${baseSystem}\n\n${"━".repeat(40)}\n📚 بيانات RAG الطبية الموثوقة:\n${ragContext}\n${"━".repeat(40)}\nاستند لهذه البيانات في إجابتك وأشر إليها.`
      : baseSystem;

    // ── Step 3: Run all models in parallel ──
    const responses = { claude:null, gpt4:null, biogpt:null };
    const available = CBG.getAvailableModels();

    await Promise.allSettled([
      MODELS.claude({ messages, system:enrichedSystem, maxTokens })
        .then(r=>{ responses.claude=r; })
        .catch(()=>{}),

      available.includes("gpt4")
        ? MODELS.gpt4({ messages, system:enrichedSystem, maxTokens })
            .then(r=>{ responses.gpt4=r; })
            .catch(()=>{})
        : Promise.resolve(),

      available.includes("biogpt")
        ? MODELS.biogpt({ messages, system:enrichedSystem, maxTokens })
            .then(r=>{ responses.biogpt=r; })
            .catch(()=>{})
        : Promise.resolve(),
    ]);

    // ── Step 4: True analytical consensus ──
    return Consensus.buildFinal(responses, ragContext, ragCitations);
  },

  statusBadge() {
    const m  = CBG.getAvailableModels();
    const mp = { claude:"C", gpt4:"G", biogpt:"B" };
    return "CBG[" + m.map(x=>mp[x]).join("+") + "]";
  },
};

// ── LEGACY WRAPPER ─────────────────────────────
async function callAI({ messages, system="", maxTokens=900, useRAG=true }) {
  return CBG.call({ messages, system, maxTokens, useRAG });
}
