// ── CAMERA ───────────────────────────────────
function Camera({onCapture,onClose}){
  const vr=useRef(null); const [stream,setStream]=useState(null); const [face,setFace]=useState("user");
  useEffect(()=>{
    let s;
    (async()=>{
      s=await navigator.mediaDevices.getUserMedia({video:{facingMode:face}}).catch(()=>null);
      if(s){setStream(s);if(vr.current)vr.current.srcObject=s;}
    })();
    return()=>s?.getTracks().forEach(t=>t.stop());
  },[face]);
  const snap=()=>{
    const c=document.createElement("canvas");
    c.width=vr.current.videoWidth;c.height=vr.current.videoHeight;
    c.getContext("2d").drawImage(vr.current,0,0);
    onCapture(c.toDataURL("image/jpeg",.88));
    stream?.getTracks().forEach(t=>t.stop());
    onClose();
  };
  return(
    <div style={{position:"fixed",inset:0,background:"#000d",zIndex:9999,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:16}}>
      <video ref={vr} autoPlay playsInline muted style={{width:"100%",maxWidth:480,borderRadius:16}}/>
      <div style={{display:"flex",gap:12,marginTop:16}}>
        <Btn onClick={()=>setFace(f=>f==="user"?"environment":"user")} color={C.accent2} size="sm">🔄</Btn>
        <Btn onClick={snap} color={C.accent3}>📸 التقاط</Btn>
        <Btn onClick={onClose} color={C.danger} size="sm">✕</Btn>
      </div>
      <div style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",
        width:220,height:220,border:`2px solid ${C.accent}`,borderRadius:16,pointerEvents:"none"}}>
        <div style={{position:"absolute",top:0,left:0,right:0,height:3,background:C.accent+"aa",
          animation:"scanLine 2.5s linear infinite"}}/>
      </div>
    </div>
  );
}

// ── VOICE RECORDER ───────────────────────────
function useVoice(onDone){
  const [rec,setRec]=useState(false); const [secs,setSecs]=useState(0);
  const mr=useRef(null); const timer=useRef(null); const chunks=useRef([]);
  const start=async()=>{
    try{
      const stream=await navigator.mediaDevices.getUserMedia({audio:true});
      chunks.current=[];
      mr.current=new MediaRecorder(stream);
      mr.current.ondataavailable=e=>chunks.current.push(e.data);
      mr.current.onstop=()=>{
        const blob=new Blob(chunks.current,{type:"audio/webm"});
        onDone(new File([blob],"voice_"+Date.now()+".webm",{type:"audio/webm"}));
        stream.getTracks().forEach(t=>t.stop());
      };
      mr.current.start(); setRec(true); setSecs(0);
      timer.current=setInterval(()=>setSecs(s=>s+1),1000);
    }catch{alert("لا يمكن الوصول للمايكروفون");}
  };
  const stop=()=>{mr.current?.state==="recording"&&mr.current.stop();clearInterval(timer.current);setRec(false);setSecs(0);};
  return{rec,secs,start,stop};
}

