// ══════════════════════════════════════════════════
//  📱  OUR APPS PAGE — public facing apps showcase
// ══════════════════════════════════════════════════
function OurAppsPage({cfg}){
  const apps = (cfg.ourApps||[]).filter(a=>a.enabled!==false);

  if(apps.length===0) return(
    <div className="fadeIn" style={{textAlign:"center",padding:"60px 24px"}}>
      <div style={{fontSize:60,marginBottom:16}}>📱</div>
      <div style={{fontWeight:700,fontSize:18,color:C.text,marginBottom:8}}>تطبيقاتنا</div>
      <div style={{fontSize:13,color:C.muted}}>لا توجد تطبيقات منشورة بعد</div>
    </div>
  );

  const cats=[...new Set(apps.map(a=>a.category||"other"))];

  return(
    <div className="fadeIn">
      {/* Header */}
      <div style={{background:"linear-gradient(135deg,#060d1a,#0c1830)",borderRadius:18,
        padding:"20px 16px",marginBottom:16,border:`1px solid ${C.accent2}44`,
        position:"relative",overflow:"hidden"}}>
        <div style={{position:"absolute",top:-30,left:-30,width:120,height:120,
          background:`${C.accent2}15`,borderRadius:"50%",filter:"blur(40px)"}}/>
        <div style={{position:"relative"}}>
          <div style={{fontSize:36,marginBottom:8}}>📱</div>
          <div style={{fontWeight:900,fontSize:20,color:C.text}}>تطبيقاتنا</div>
          <div style={{fontSize:12,color:C.muted,marginTop:4}}>
            مجموعة تطبيقاتنا الصحية على جميع المنصات
          </div>
        </div>
      </div>

      {cats.map(cat=>{
        const catApps=apps.filter(a=>(a.category||"other")===cat);
        const catLabel={health:"🏥 الصحة",fitness:"💪 اللياقة",nutrition:"🥗 التغذية",
          mental:"🧠 الصحة النفسية",medical:"⚕️ الطبي",other:"📱 أخرى"}[cat]||cat;
        return(
          <div key={cat} style={{marginBottom:20}}>
            <div style={{fontSize:13,fontWeight:700,color:C.muted,
              marginBottom:10,paddingBottom:6,borderBottom:`1px solid ${C.border}`}}>
              {catLabel}
            </div>
            {catApps.map(app=>(
              <div key={app.id||app.name}
                style={{background:C.card,border:`1px solid ${C.border}`,
                  borderRadius:16,padding:14,marginBottom:10,
                  transition:"all .2s"}}>
                <div style={{display:"flex",gap:14,alignItems:"flex-start"}}>
                  {/* Icon */}
                  <div style={{width:56,height:56,borderRadius:14,flexShrink:0,
                    background:`linear-gradient(135deg,${app.color||C.accent}22,${app.color||C.accent2}22)`,
                    border:`1px solid ${app.color||C.accent}44`,
                    display:"flex",alignItems:"center",justifyContent:"center",fontSize:28}}>
                    {app.icon||"📱"}
                  </div>
                  {/* Info */}
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontWeight:800,fontSize:15,color:C.text}}>
                      {app.nameAr||app.name}
                    </div>
                    {app.name && app.nameAr && (
                      <div style={{fontSize:11,color:C.muted}}>{app.name}</div>
                    )}
                    {app.desc&&(
                      <div style={{fontSize:12,color:C.muted,marginTop:4,lineHeight:1.6}}>
                        {app.desc}
                      </div>
                    )}
                    {/* Store buttons */}
                    <div style={{display:"flex",gap:8,marginTop:10,flexWrap:"wrap"}}>
                      {app.androidUrl&&(
                        <a href={app.androidUrl} target="_blank" rel="noopener noreferrer"
                          style={{display:"flex",alignItems:"center",gap:6,
                            background:"#3ddc8422",border:"1px solid #3ddc8444",
                            borderRadius:10,padding:"7px 12px",
                            textDecoration:"none",color:"#3ddc84",fontSize:12,fontWeight:600}}>
                          <span style={{fontSize:16}}>🤖</span> Google Play
                        </a>
                      )}
                      {app.iosUrl&&(
                        <a href={app.iosUrl} target="_blank" rel="noopener noreferrer"
                          style={{display:"flex",alignItems:"center",gap:6,
                            background:"#007aff22",border:"1px solid #007aff44",
                            borderRadius:10,padding:"7px 12px",
                            textDecoration:"none",color:"#007aff",fontSize:12,fontWeight:600}}>
                          <span style={{fontSize:16}}>🍎</span> App Store
                        </a>
                      )}
                      {app.webUrl&&(
                        <a href={app.webUrl} target="_blank" rel="noopener noreferrer"
                          style={{display:"flex",alignItems:"center",gap:6,
                            background:`${C.accent}18`,border:`1px solid ${C.accent}44`,
                            borderRadius:10,padding:"7px 12px",
                            textDecoration:"none",color:C.accent,fontSize:12,fontWeight:600}}>
                          <span style={{fontSize:16}}>🌐</span> الموقع
                        </a>
                      )}
                      {/* No links placeholder */}
                      {!app.androidUrl&&!app.iosUrl&&!app.webUrl&&(
                        <span style={{fontSize:11,color:C.muted,padding:"6px 0"}}>
                          🔜 قريباً
                        </span>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        );
      })}

      {/* Footer */}
      <div style={{textAlign:"center",padding:"12px 0",fontSize:11,color:C.muted}}>
        {apps.length} تطبيق متاح
      </div>
    </div>
  );
}


