//  🔒  PRIVACY PAGE — سياسة الخصوصية (محسّنة بالكامل)
// ══════════════════════════════════════════════════════════════════
function PrivacyPage({onBack, lang="ar"}){
  const [section, setSection] = useState(null);
  const sections = lang==="ar" ? [
    {id:"collect",t:"البيانات التي نجمعها",i:"📋",
     b:`نجمع البيانات التالية:\n• بيانات الحساب: الاسم، البريد الإلكتروني، رقم الهاتف\n• بيانات الصحة: نتائج التحليلات، قياسات العلامات الحيوية\n• بيانات الاستخدام: الصفحات المزارة، الميزات المستخدمة\n• بيانات الجهاز: نوع الجهاز، نظام التشغيل، معرّف التطبيق\n• الصور والصوت: فقط عند استخدام ميزات التحليل ولا تُخزَّن`},
    {id:"use",t:"كيف نستخدم بياناتك",i:"🔄",
     b:`نستخدم بياناتك لـ:\n• تقديم خدمات التحليل الصحي المخصصة\n• تحسين دقة نماذج الذكاء الاصطناعي\n• إرسال إشعارات الخدمة والتذكيرات\n• معالجة المدفوعات بأمان\n• الامتثال للمتطلبات القانونية\n\nلا نبيع بياناتك أو نشاركها مع أطراف ثالثة لأغراض تجارية.`},
    {id:"store",t:"تخزين وحماية البيانات",i:"🔐",
     b:`• تُخزَّن بياناتك في Supabase (AWS) مشفرة بـ AES-256\n• نستخدم HTTPS لجميع الاتصالات\n• المصادقة بـ JWT tokens آمنة\n• لا يمكن لأي موظف الوصول لبياناتك دون تفويض\n• نسخ احتياطية يومية مشفرة\n• يمكنك طلب حذف بياناتك بالكامل في أي وقت`},
    {id:"camera",t:"الكاميرا والميكروفون",i:"📷",
     b:`• نصل للكاميرا فقط عند تفعيلك ميزات التحليل (تحليل الجلد، الدم، الأوردة)\n• نصل للميكروفون فقط أثناء الدردشة الصوتية\n• لا نحفظ الصور أو التسجيلات الصوتية على خوادمنا\n• يمكنك إلغاء هذه الأذونات في أي وقت من إعدادات الجهاز`},
    {id:"ai",t:"نماذج الذكاء الاصطناعي",i:"🤖",
     b:`نرسل استفساراتك النصية لـ:\n• Claude (Anthropic) — سياسة الخصوصية: anthropic.com/privacy\n• GPT-4 (OpenAI) — سياسة الخصوصية: openai.com/privacy\n• BioGPT (Microsoft) — سياسة الخصوصية: microsoft.com/privacy\n\nلا نرسل صورك أو تسجيلاتك الصوتية لهذه الخدمات.`},
    {id:"rights",t:"حقوقك",i:"⚖️",
     b:`يحق لك:\n• الاطلاع على بياناتك المخزنة\n• تصحيح المعلومات الخاطئة\n• طلب حذف حسابك وجميع بياناتك\n• تصدير بياناتك بصيغة FHIR R4 أو CSV\n• رفع شكوى لجهة حماية البيانات في بلدك\n• إلغاء الاشتراك في أي وقت\n\nللتواصل: privacy@healthsphere.app`},
    {id:"cookies",t:"ملفات تعريف الارتباط",i:"🍪",
     b:`نستخدم ملفات تعريف الارتباط الضرورية فقط لـ:\n• الحفاظ على جلسة تسجيل الدخول\n• تخزين تفضيلات اللغة والإعدادات\n• قياس أداء التطبيق بشكل مجهول الهوية\n\nلا نستخدم ملفات تعريف الارتباط للإعلانات.`},
    {id:"children",t:"خصوصية الأطفال",i:"👶",
     b:`HealthSphere غير مخصص للأطفال دون سن 13 عاماً. لا نجمع بيانات الأطفال عمداً. إذا اكتشفت أن طفلاً قدّم بياناته، يرجى التواصل معنا فوراً لحذفها.`},
    {id:"changes",t:"تغييرات السياسة",i:"📝",
     b:`قد نحدّث سياسة الخصوصية من وقت لآخر. سنخطرك عبر إشعار داخل التطبيق. الاستمرار في استخدام التطبيق بعد التحديث يعني موافقتك على السياسة الجديدة.\n\nآخر تحديث: مارس 2026`},
  ] : [
    {id:"collect",t:"Data We Collect",i:"📋",
     b:`We collect the following data:\n• Account data: name, email, phone number\n• Health data: analysis results, vital sign measurements\n• Usage data: pages visited, features used\n• Device data: device type, OS, app identifier\n• Images and audio: only during analysis features, not stored`},
    {id:"use",t:"How We Use Your Data",i:"🔄",
     b:`We use your data to:\n• Provide personalized health analysis services\n• Improve AI model accuracy\n• Send service notifications and reminders\n• Process payments securely\n• Comply with legal requirements\n\nWe do not sell or share your data with third parties for commercial purposes.`},
    {id:"store",t:"Data Storage & Security",i:"🔐",
     b:`• Your data is stored in Supabase (AWS) encrypted with AES-256\n• All communications use HTTPS\n• Authentication via secure JWT tokens\n• No employee can access your data without authorization\n• Daily encrypted backups\n• You can request full deletion of your data at any time`},
    {id:"camera",t:"Camera & Microphone",i:"📷",
     b:`• We access the camera only when you activate analysis features\n• We access the microphone only during voice chat\n• We do not store images or audio recordings on our servers\n• You can revoke these permissions anytime in device settings`},
    {id:"ai",t:"AI Models",i:"🤖",
     b:`We send your text queries to:\n• Claude (Anthropic) — Privacy: anthropic.com/privacy\n• GPT-4 (OpenAI) — Privacy: openai.com/privacy\n• BioGPT (Microsoft) — Privacy: microsoft.com/privacy\n\nWe do not send your images or voice recordings to these services.`},
    {id:"rights",t:"Your Rights",i:"⚖️",
     b:`You have the right to:\n• Access your stored data\n• Correct incorrect information\n• Request deletion of your account and all data\n• Export your data in FHIR R4 or CSV format\n• File a complaint with your local data protection authority\n• Cancel your subscription at any time\n\nContact: privacy@healthsphere.app`},
    {id:"cookies",t:"Cookies",i:"🍪",
     b:`We use only essential cookies for:\n• Maintaining your login session\n• Storing language and settings preferences\n• Measuring app performance anonymously\n\nWe do not use cookies for advertising.`},
    {id:"children",t:"Children's Privacy",i:"👶",
     b:`HealthSphere is not intended for children under 13. We do not knowingly collect children's data. If you discover a child has submitted their data, please contact us immediately for deletion.`},
    {id:"changes",t:"Policy Changes",i:"📝",
     b:`We may update this Privacy Policy periodically. We will notify you via in-app notification. Continued use of the app after the update means you agree to the new policy.\n\nLast updated: March 2026`},
  ];

  return(
    <div className="fadeIn" style={{maxWidth:640,margin:"0 auto"}}>
      <button onClick={onBack}
        style={{background:"none",color:C.accent,fontSize:13,border:"none",cursor:"pointer",
          display:"flex",alignItems:"center",gap:4,marginBottom:16,
          fontFamily:"'Tajawal',sans-serif"}}>
        {lang==="ar"?"← رجوع":"← Back"}
      </button>
      <div style={{fontWeight:900,fontSize:20,marginBottom:4}}>
        🔒 {lang==="ar"?"سياسة الخصوصية":"Privacy Policy"}
      </div>
      <div style={{fontSize:11,color:C.muted,marginBottom:20}}>
        {lang==="ar"?"آخر تحديث: مارس 2026":"Last updated: March 2026"}
      </div>
      {sections.map((s,i)=>(
        <div key={s.id} style={{marginBottom:8,borderRadius:12,overflow:"hidden",
          border:`1px solid ${section===i?C.accent+"55":C.border}`,
          background:section===i?`${C.accent}06`:C.card}}>
          <button onClick={()=>setSection(p=>p===i?null:i)}
            style={{width:"100%",padding:"13px 14px",background:"none",
              display:"flex",justifyContent:"space-between",alignItems:"center",
              color:C.text,fontFamily:"'Tajawal',sans-serif",fontSize:13,fontWeight:600,
              border:"none",cursor:"pointer"}}>
            <span style={{display:"flex",gap:8,alignItems:"center"}}>
              <span>{s.i}</span><span>{s.t}</span>
            </span>
            <span style={{color:C.accent,fontSize:14}}>{section===i?"▲":"▼"}</span>
          </button>
          {section===i&&(
            <div style={{padding:"0 14px 14px",fontSize:12,
              color:C.muted,lineHeight:2,borderTop:`1px solid ${C.border}`}}>
              <div style={{paddingTop:10,whiteSpace:"pre-line"}}>{s.b}</div>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

