// Smart T() function - uses AUTO_TRANS first, then TRANS dict
function AT(key, lang="ar") {
  if(!lang) lang="ar";
  const entry = AUTO_TRANS[key];
  if(entry) return entry[lang] || entry.ar;
  return T(key, lang);
}

// ══════════════════════════════════════════════════════════════════
//  📄  ADMIN ABOUT/PRIVACY/TERMS EDITOR TAB
//  يمكن الأدمن من تعديل كل صفحات المحتوى
// ══════════════════════════════════════════════════════════════════
function AdminContentTab({cfg,sv}){
  const [tab2,   setTab2]  = useState("about");
  const [saved,  setSaved] = useState(false);
  const [links,  setLinks] = useState(()=>DB.get("hsp_page_links",{
    privacy:"",terms:"",about:"",help:"",app_store:"",play_store:"",website:""
  }));

  // Content state - loaded from DB with defaults
  const [aboutAr,  setAboutAr]  = useState(()=>DB.get("content_about_ar",""));
  const [aboutEn,  setAboutEn]  = useState(()=>DB.get("content_about_en",""));
  const [privAr,   setPrivAr]   = useState(()=>DB.get("content_privacy_ar",""));
  const [privEn,   setPrivEn]   = useState(()=>DB.get("content_privacy_en",""));
  const [termsAr,  setTermsAr]  = useState(()=>DB.get("content_terms_ar",""));
  const [termsEn,  setTermsEn]  = useState(()=>DB.get("content_terms_en",""));
  const [helpAr,   setHelpAr]   = useState(()=>DB.get("content_help_ar",""));
  const [helpEn,   setHelpEn]   = useState(()=>DB.get("content_help_en",""));
  const [lang2,    setLang2]    = useState("ar");

  const saveAll=()=>{
    DB.set("content_about_ar",aboutAr);  DB.set("content_about_en",aboutEn);
    DB.set("content_privacy_ar",privAr); DB.set("content_privacy_en",privEn);
    DB.set("content_terms_ar",termsAr);  DB.set("content_terms_en",termsEn);
    DB.set("content_help_ar",helpAr);    DB.set("content_help_en",helpEn);
    DB.set("hsp_page_links",links);
    setSaved(true); setTimeout(()=>setSaved(false),2500);
  };

  // Generate shareable link for any page
  const generateLink=(page)=>{
    const base=window.location.href.replace(/[?#].*/,"").replace(/index\.html$/,"");
    return `${base}#${page}`;
  };

  const copyLink=(page)=>{
    const url=links[page]||generateLink(page);
    navigator.clipboard?.writeText(url).then(()=>alert(`✅ تم نسخ رابط ${page}`));
  };

  const pages=[
    {id:"about",  label:"عن التطبيق",       icon:"ℹ️", ar:aboutAr,  setAr:setAboutAr,  en:aboutEn,  setEn:setAboutEn,  linkKey:"about"},
    {id:"privacy",label:"سياسة الخصوصية",   icon:"🔒", ar:privAr,   setAr:setPrivAr,   en:privEn,   setEn:setPrivEn,   linkKey:"privacy"},
    {id:"terms",  label:"شروط الاستخدام",   icon:"📋", ar:termsAr,  setAr:setTermsAr,  en:termsEn,  setEn:setTermsEn,  linkKey:"terms"},
    {id:"help",   label:"المساعدة",         icon:"❓", ar:helpAr,   setAr:setHelpAr,   en:helpEn,   setEn:setHelpEn,   linkKey:"help"},
  ];

  const currentPage=pages.find(p=>p.id===tab2);

  return(
    <div>
      {/* Header */}
      <div style={{background:"linear-gradient(135deg,#060d1a,#0a1020)",
        borderRadius:14,padding:14,marginBottom:12,border:`1px solid ${C.accent2}33`}}>
        <div style={{fontWeight:800,fontSize:15,color:C.accent2,marginBottom:4}}>
          📝 إدارة المحتوى والصفحات
        </div>
        <div style={{fontSize:11,color:C.muted}}>
          عدّل نصوص كل صفحة بالعربي والإنجليزي · أنشئ روابط مباشرة لكل صفحة
        </div>
      </div>

      {saved&&(
        <div style={{padding:"8px 14px",background:`${C.accent3}15`,borderRadius:10,
          marginBottom:10,fontSize:12,color:C.accent3,border:`1px solid ${C.accent3}33`}}>
          ✅ تم حفظ كل التغييرات بنجاح
        </div>
      )}

      {/* Page tabs */}
      <div style={{display:"flex",gap:6,marginBottom:12,flexWrap:"wrap"}}>
        {pages.map(p=>(
          <button key={p.id} onClick={()=>setTab2(p.id)}
            style={{padding:"6px 14px",borderRadius:20,cursor:"pointer",
              fontFamily:"'Tajawal',sans-serif",fontSize:12,fontWeight:600,
              background:tab2===p.id?`${C.accent2}22`:C.card2,
              border:`1.5px solid ${tab2===p.id?C.accent2:C.border}`,
              color:tab2===p.id?C.accent2:C.muted}}>
            {p.icon} {p.label}
          </button>
        ))}
      </div>

      {currentPage&&(
        <div>
          {/* Link Section */}
          <Card style={{marginBottom:12,background:`${C.accent}06`,border:`1px solid ${C.accent}22`}}>
            <div style={{fontWeight:700,color:C.accent,marginBottom:10,fontSize:13}}>
              🔗 رابط صفحة "{currentPage.label}"
            </div>
            <div style={{fontSize:11,color:C.muted,marginBottom:8,lineHeight:1.6}}>
              استخدم هذا الرابط في متجر Google Play أو App Store أو لمشاركته مع المستخدمين
            </div>

            {/* Auto-generated link */}
            <div style={{padding:"8px 12px",background:C.card2,borderRadius:8,
              fontFamily:"monospace",fontSize:10,color:C.accent3,marginBottom:8,
              wordBreak:"break-all",border:`1px solid ${C.border}`}}>
              {generateLink(currentPage.id)}
            </div>

            {/* Custom link override */}
            <div style={{marginBottom:8}}>
              <div style={{fontSize:10,color:C.muted,marginBottom:4}}>
                رابط مخصص (للاستضافة الخارجية — اختياري):
              </div>
              <div style={{display:"flex",gap:6}}>
                <input value={links[currentPage.linkKey]||""}
                  onChange={e=>setLinks(p=>({...p,[currentPage.linkKey]:e.target.value}))}
                  placeholder="https://healthsphere.app/privacy"
                  style={{flex:1,padding:"8px 10px",borderRadius:8,
                    background:C.card2,border:`1px solid ${C.border}`,
                    color:C.text,fontSize:11,fontFamily:"monospace"}}/>
                <button onClick={()=>copyLink(currentPage.id)}
                  style={{padding:"8px 12px",borderRadius:8,cursor:"pointer",
                    background:`${C.accent}22`,border:`1px solid ${C.accent}44`,
                    color:C.accent,fontSize:11,whiteSpace:"nowrap",
                    fontFamily:"'Tajawal',sans-serif"}}>
                  📋 نسخ
                </button>
              </div>
            </div>

            {/* Google Play specific */}
            {currentPage.id==="privacy"&&(
              <div style={{padding:"8px 12px",background:`${C.warn}10`,borderRadius:8,
                border:`1px solid ${C.warn}30`,fontSize:10,color:C.warn,lineHeight:1.7}}>
                ℹ️ <strong>Google Play يتطلب:</strong> رابط سياسة الخصوصية يجب أن يكون
                رابطاً عاماً (HTTPS). انسخ الرابط المُنشأ أعلاه أو أدخل رابط موقعك.
              </div>
            )}
          </Card>

          {/* Language toggle */}
          <div style={{display:"flex",gap:8,marginBottom:12,alignItems:"center"}}>
            <div style={{fontSize:12,color:C.muted}}>تعديل النص بـ:</div>
            {["ar","en"].map(l=>(
              <button key={l} onClick={()=>setLang2(l)}
                style={{padding:"5px 14px",borderRadius:20,cursor:"pointer",
                  fontFamily:"'Tajawal',sans-serif",fontSize:11,fontWeight:700,
                  background:lang2===l?`${C.accent}22`:C.card2,
                  border:`1.5px solid ${lang2===l?C.accent:C.border}`,
                  color:lang2===l?C.accent:C.muted}}>
                {l==="ar"?"🇸🇦 العربية":"🇺🇸 English"}
              </button>
            ))}
          </div>

          {/* Text editor */}
          <Card style={{marginBottom:12}}>
            <div style={{fontWeight:700,marginBottom:8,fontSize:13,color:C.accent2}}>
              ✏️ تعديل نص "{currentPage.label}" — {lang2==="ar"?"العربية":"English"}
            </div>
            <div style={{fontSize:10,color:C.muted,marginBottom:6}}>
              يمكنك كتابة HTML بسيط مثل: &lt;b&gt;نص عريض&lt;/b&gt; أو أسطر جديدة بـ ↵
            </div>
            <textarea
              value={lang2==="ar"?currentPage.ar:currentPage.en}
              onChange={e=>lang2==="ar"?currentPage.setAr(e.target.value):currentPage.setEn(e.target.value)}
              placeholder={lang2==="ar"
                ?"اكتب المحتوى بالعربية هنا..."
                :"Write content in English here..."}
              rows={12}
              style={{width:"100%",background:C.card2,border:`1px solid ${C.border}`,
                borderRadius:10,padding:"10px 12px",color:C.text,fontSize:12,
                fontFamily:lang2==="ar"?"'Tajawal',sans-serif":"monospace",
                lineHeight:1.8,resize:"vertical",direction:lang2==="ar"?"rtl":"ltr"}}/>
            <div style={{fontSize:10,color:C.muted,marginTop:4}}>
              {lang2==="ar"
                ?(currentPage.ar||"").length
                :(currentPage.en||"").length} حرف
            </div>
          </Card>

          {/* Preview */}
          {((lang2==="ar"&&currentPage.ar)||(lang2==="en"&&currentPage.en))&&(
            <Card style={{marginBottom:12,background:`${C.accent}04`}}>
              <div style={{fontWeight:700,color:C.accent,marginBottom:8,fontSize:12}}>
                👁️ معاينة
              </div>
              <div style={{fontSize:12,color:C.muted,lineHeight:1.9,
                direction:lang2==="ar"?"rtl":"ltr"}}
                dangerouslySetInnerHTML={{
                  __html:(lang2==="ar"?currentPage.ar:currentPage.en)
                    .replace(/\n/g,"<br/>")
                }}>
              </div>
            </Card>
          )}
        </div>
      )}

      {/* All links summary */}
      <Card style={{marginBottom:14}}>
        <div style={{fontWeight:700,color:C.gold,marginBottom:10,fontSize:13}}>
          🔗 جميع روابط الصفحات
        </div>
        <div style={{fontSize:10,color:C.muted,marginBottom:10}}>
          استخدم هذه الروابط في متاجر التطبيقات والمواقع الرسمية
        </div>
        {[
          {key:"privacy",  label:"سياسة الخصوصية",  icon:"🔒"},
          {key:"terms",    label:"شروط الاستخدام",  icon:"📋"},
          {key:"about",    label:"عن التطبيق",       icon:"ℹ️"},
          {key:"help",     label:"المساعدة",         icon:"❓"},
          {key:"app_store",label:"App Store",        icon:"🍎"},
          {key:"play_store",label:"Google Play",     icon:"🤖"},
          {key:"website",  label:"الموقع الرسمي",   icon:"🌐"},
        ].map(item=>(
          <div key={item.key} style={{marginBottom:8}}>
            <div style={{fontSize:10,color:C.muted,marginBottom:3}}>
              {item.icon} {item.label}
            </div>
            <div style={{display:"flex",gap:6}}>
              <input value={links[item.key]||""}
                onChange={e=>setLinks(p=>({...p,[item.key]:e.target.value}))}
                placeholder={item.key==="privacy"?generateLink("privacy"):
                             item.key==="terms"?generateLink("terms"):
                             item.key==="about"?generateLink("about"):
                             `https://...`}
                style={{flex:1,padding:"6px 10px",borderRadius:8,
                  background:C.card2,border:`1px solid ${C.border}`,
                  color:C.text,fontSize:10,fontFamily:"monospace"}}/>
              <button onClick={()=>{
                const url=links[item.key]||(["privacy","terms","about","help"].includes(item.key)?generateLink(item.key):"");
                if(url) navigator.clipboard?.writeText(url).then(()=>{});
              }} style={{padding:"6px 10px",borderRadius:8,cursor:"pointer",
                background:`${C.accent}15`,border:`1px solid ${C.accent}33`,
                color:C.accent,fontSize:10}}>
                📋
              </button>
            </div>
          </div>
        ))}
      </Card>

      <button onClick={saveAll}
        style={{width:"100%",padding:14,borderRadius:14,cursor:"pointer",
          background:saved?"linear-gradient(135deg,#10d98a,#059669)":"linear-gradient(135deg,#7c3aed,#5b21b6)",
          border:"none",color:"#fff",fontWeight:800,fontSize:14,
          fontFamily:"'Tajawal',sans-serif",transition:"all .3s"}}>
        {saved?"✅ محفوظ!":"💾 حفظ كل التغييرات"}
      </button>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════
//  👥  ADMIN USERS TAB — إدارة كاملة للمستخدمين
// ══════════════════════════════════════════════════════════════════
function AdminUsersTab({cfg,sv}){
  const [users,    setUsers]   = useState(()=>DB.get("auth_users",[]));
  const [search,   setSearch]  = useState("");
  const [selUser,  setSelUser] = useState(null);
  const [msg,      setMsg]     = useState(null);
  const [tab2,     setTab2]    = useState("list");
  const [editData, setEditData]= useState({});
  const [showDel,  setShowDel] = useState(null);

  const pendingPayments = DB.get("pending_payments",[]);

  const filtered = users.filter(u=>
    !search ||
    (u.name||"").toLowerCase().includes(search.toLowerCase()) ||
    (u.email||"").toLowerCase().includes(search.toLowerCase()) ||
    (u.phone||"").includes(search)
  );

  const showMsg=(ok,text)=>{
    setMsg({ok,text});
    setTimeout(()=>setMsg(null),3000);
  };

  const saveUser=(uid)=>{
    const updates=editData[uid]||{};
    const newUsers=users.map(u=>u.id===uid?{...u,...updates}:u);
    setUsers(newUsers);
    DB.set("auth_users",newUsers);
    setSelUser(null);
    setEditData(p=>({...p,[uid]:{}}));
    showMsg(true,"✅ تم تحديث بيانات المستخدم");
  };

  const deleteUser=(uid)=>{
    // Delete from users list
    const newUsers=users.filter(u=>u.id!==uid);
    setUsers(newUsers);
    DB.set("auth_users",newUsers);
    // Delete all user data
    const keysToDelete=[
      `vitals_hist_${uid}`,`bloodtest_hist_${uid}`,
      `anlys_hist_${uid}`,`chat_${uid}`,
    ];
    keysToDelete.forEach(k=>localStorage.removeItem(k));
    setSelUser(null);
    setShowDel(null);
    showMsg(true,"✅ تم حذف المستخدم وجميع بياناته");
  };

  const deleteAllUserData=(uid)=>{
    // Nuclear option - delete everything
    const allKeys=Object.keys(localStorage).filter(k=>
      k.includes(uid)||k.startsWith(`user_${uid}`)
    );
    allKeys.forEach(k=>localStorage.removeItem(k));
    showMsg(true,`✅ تم حذف ${allKeys.length} سجل للمستخدم`);
  };

  const approvePlan=(payment)=>{
    const newUsers=users.map(u=>u.id===payment.userId
      ?{...u,plan:payment.plan,
        planExpiry:Date.now()+365*24*3600*1000,
        planActivatedAt:Date.now(),
        status:"active"}
      :u);
    setUsers(newUsers);
    DB.set("auth_users",newUsers);
    const newPending=pendingPayments.filter(p=>p.id!==payment.id);
    DB.set("pending_payments",newPending);
    const log=DB.get("payment_log",[]);
    DB.set("payment_log",[{...payment,approved:true,approvedAt:Date.now()},...log]);
    showMsg(true,`✅ تم تفعيل خطة "${payment.plan}" للمستخدم ${payment.userEmail}`);
  };

  const planColor=p=>({
    free:"#4a6080",personal:C.accent,family:C.accent2,
    corporate:"#f59e0b",enterprise:C.gold,whitelabel:"#a855f7",
    hospital:C.danger,reseller:"#ec4899"
  }[p]||C.muted);

  const planIcon=p=>({
    free:"🆓",personal:"👤",family:"👨‍👩‍👧",corporate:"🏢",
    enterprise:"🏗️",whitelabel:"🏷️",hospital:"🏥",reseller:"🔄"
  }[p]||"👤");

  const updateEdit=(uid,key,val)=>setEditData(p=>({...p,[uid]:{...(p[uid]||{}),[key]:val}}));

  return(
    <div>
      {/* Header */}
      <div style={{background:"linear-gradient(135deg,#0a0f20,#060d18)",
        borderRadius:14,padding:14,marginBottom:12,border:`1px solid ${C.accent}33`}}>
        <div style={{fontWeight:800,fontSize:15,color:C.accent,marginBottom:6}}>
          👥 إدارة المستخدمين
        </div>
        <div style={{display:"flex",gap:12,fontSize:11,flexWrap:"wrap"}}>
          {[
            {l:"الإجمالي",v:users.length,c:C.text},
            {l:"مدفوعون",v:users.filter(u=>u.plan&&u.plan!=="free").length,c:C.gold},
            {l:"نشطون",v:users.filter(u=>u.status!=="suspended"&&u.status!=="banned").length,c:C.accent3},
            {l:"معلقة",v:pendingPayments.length,c:C.warn},
          ].map(s=>(
            <div key={s.l} style={{padding:"4px 10px",borderRadius:20,
              background:`${s.c}15`,border:`1px solid ${s.c}33`}}>
              <span style={{color:s.c,fontWeight:800}}>{s.v}</span>
              <span style={{color:C.muted,marginRight:4}}> {s.l}</span>
            </div>
          ))}
        </div>
      </div>

      {msg&&(
        <div style={{padding:"8px 14px",borderRadius:10,marginBottom:10,
          background:msg.ok?`${C.accent3}15`:`${C.danger}15`,
          border:`1px solid ${msg.ok?C.accent3:C.danger}33`,
          fontSize:12,color:msg.ok?C.accent3:C.danger}}>{msg.text}</div>
      )}

      {pendingPayments.length>0&&tab2==="list"&&(
        <div onClick={()=>setTab2("pending")}
          style={{padding:"10px 14px",background:`${C.warn}12`,borderRadius:10,
          marginBottom:10,border:`1px solid ${C.warn}44`,fontSize:12,
          color:C.warn,cursor:"pointer",display:"flex",gap:8,alignItems:"center"}}>
          <span style={{fontSize:20}}>⚠️</span>
          <span><strong>{pendingPayments.length}</strong> دفعة تنتظر الموافقة — انقر للمراجعة</span>
        </div>
      )}

      {/* Tabs */}
      <Tabs tabs={[
        {id:"list",    ar:`👥 المستخدمون (${users.length})`},
        {id:"pending", ar:`💳 دفعات معلقة (${pendingPayments.length})`},
        {id:"log",     ar:"📋 سجل الدفعات"},
      ]} active={tab2} onChange={setTab2}/>

      <div style={{marginTop:12}}>

      {/* ── USERS LIST ── */}
      {tab2==="list"&&(
        <div>
          <div style={{display:"flex",gap:8,marginBottom:10}}>
            <div style={{flex:1,position:"relative"}}>
              <span style={{position:"absolute",right:10,top:"50%",
                transform:"translateY(-50%)",fontSize:14,color:C.muted}}>🔍</span>
              <input value={search} onChange={e=>setSearch(e.target.value)}
                placeholder="بحث بالاسم أو البريد أو الهاتف..."
                style={{width:"100%",padding:"8px 36px 8px 12px",borderRadius:10,
                  background:C.card2,border:`1px solid ${C.border}`,
                  color:C.text,fontSize:12,fontFamily:"'Tajawal',sans-serif"}}/>
            </div>
            {search&&(
              <button onClick={()=>setSearch("")}
                style={{padding:"8px 12px",borderRadius:10,cursor:"pointer",
                  background:C.card2,border:`1px solid ${C.border}`,color:C.muted}}>✕</button>
            )}
          </div>

          {filtered.length===0?(
            <div style={{textAlign:"center",padding:30,color:C.muted}}>
              <div style={{fontSize:36,marginBottom:8}}>👥</div>
              {search?"لا نتائج للبحث":"لا يوجد مستخدمون بعد"}
            </div>
          ):filtered.map(u=>(
            <div key={u.id} style={{marginBottom:8}}>
              <div onClick={()=>setSelUser(p=>p===u.id?null:u.id)}
                style={{padding:"10px 12px",borderRadius:12,cursor:"pointer",
                  background:selUser===u.id?`${C.accent}08`:C.card,
                  border:`1.5px solid ${selUser===u.id?C.accent:C.border}`,
                  transition:"all .2s"}}>
                <div style={{display:"flex",gap:10,alignItems:"center"}}>
                  <div style={{width:38,height:38,borderRadius:10,flexShrink:0,
                    background:`${planColor(u.plan||"free")}22`,
                    display:"flex",alignItems:"center",justifyContent:"center",fontSize:20}}>
                    {planIcon(u.plan||"free")}
                  </div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontWeight:700,fontSize:13,
                      whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>
                      {u.name||u.email||"مجهول"}
                    </div>
                    <div style={{fontSize:10,color:C.muted,marginTop:1}}>
                      {u.email} {u.phone&&`· ${u.phone}`}
                    </div>
                  </div>
                  <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:3}}>
                    <span style={{fontSize:9,padding:"2px 8px",borderRadius:10,
                      background:`${planColor(u.plan||"free")}22`,
                      color:planColor(u.plan||"free"),
                      border:`1px solid ${planColor(u.plan||"free")}33`}}>
                      {u.plan||"free"}
                    </span>
                    {u.status==="suspended"&&(
                      <span style={{fontSize:8,color:C.warn}}>موقوف</span>
                    )}
                  </div>
                </div>
              </div>

              {/* Expanded editor */}
              {selUser===u.id&&(
                <div style={{padding:12,background:`${C.accent}04`,borderRadius:"0 0 12px 12px",
                  border:`1px solid ${C.accent}22`,borderTop:"none",marginTop:-4}}>

                  {/* Info grid */}
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6,marginBottom:10}}>
                    {[
                      {l:"المعرّف",v:(u.id||"").slice(0,12)+"..."},
                      {l:"تاريخ التسجيل",v:new Date(u.createdAt||Date.now()).toLocaleDateString("ar-SA")},
                      {l:"النقاط",v:u.points||0},
                      {l:"انتهاء الخطة",v:u.planExpiry?new Date(u.planExpiry).toLocaleDateString("ar-SA"):"—"},
                    ].map(d=>(
                      <div key={d.l} style={{padding:"6px 8px",background:C.card2,borderRadius:8}}>
                        <div style={{fontSize:9,color:C.muted}}>{d.l}</div>
                        <div style={{fontSize:11,fontWeight:600,color:C.text}}>{d.v}</div>
                      </div>
                    ))}
                  </div>

                  {/* Editable fields */}
                  {[
                    {label:"الاسم",         field:"name",     type:"text",    val:u.name||""},
                    {label:"البريد الإلكتروني",field:"email", type:"email",   val:u.email||""},
                    {label:"رقم الهاتف",    field:"phone",    type:"tel",     val:u.phone||""},
                    {label:"النقاط",        field:"points",   type:"number",  val:u.points||0},
                  ].map(f=>(
                    <div key={f.field} style={{marginBottom:6}}>
                      <div style={{fontSize:10,color:C.muted,marginBottom:2}}>{f.label}</div>
                      <input
                        defaultValue={f.val}
                        type={f.type}
                        onChange={e=>updateEdit(u.id,f.field,f.type==="number"?+e.target.value:e.target.value)}
                        style={{width:"100%",padding:"7px 10px",borderRadius:8,
                          background:C.card2,border:`1px solid ${C.border}`,
                          color:C.text,fontSize:12,fontFamily:"'Tajawal',sans-serif"}}/>
                    </div>
                  ))}

                  {/* Plan & Status */}
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:8}}>
                    <div>
                      <div style={{fontSize:10,color:C.muted,marginBottom:2}}>الخطة</div>
                      <select
                        defaultValue={u.plan||"free"}
                        onChange={e=>updateEdit(u.id,"plan",e.target.value)}
                        style={{width:"100%",padding:"7px 8px",borderRadius:8,
                          background:C.card2,border:`1px solid ${C.border}`,
                          color:C.text,fontSize:12,fontFamily:"'Tajawal',sans-serif"}}>
                        {["free","personal","family","corporate","enterprise","whitelabel","hospital","reseller"].map(p=>(
                          <option key={p} value={p}>{p}</option>
                        ))}
                      </select>
                    </div>
                    <div>
                      <div style={{fontSize:10,color:C.muted,marginBottom:2}}>الحالة</div>
                      <select
                        defaultValue={u.status||"active"}
                        onChange={e=>updateEdit(u.id,"status",e.target.value)}
                        style={{width:"100%",padding:"7px 8px",borderRadius:8,
                          background:C.card2,border:`1px solid ${C.border}`,
                          color:C.text,fontSize:12,fontFamily:"'Tajawal',sans-serif"}}>
                        {["active","suspended","banned"].map(s=>(
                          <option key={s} value={s}>{s==="active"?"نشط":s==="suspended"?"موقوف":"محظور"}</option>
                        ))}
                      </select>
                    </div>
                  </div>

                  {/* Buttons */}
                  <div style={{display:"flex",gap:8}}>
                    <button onClick={()=>saveUser(u.id)}
                      style={{flex:2,padding:"9px",borderRadius:10,cursor:"pointer",
                        background:C.accent3,border:"none",color:"#000",
                        fontWeight:700,fontSize:12,fontFamily:"'Tajawal',sans-serif"}}>
                      ✅ حفظ التغييرات
                    </button>
                    <button onClick={()=>deleteAllUserData(u.id)}
                      style={{flex:1,padding:"9px",borderRadius:10,cursor:"pointer",
                        background:`${C.warn}22`,border:`1px solid ${C.warn}44`,
                        color:C.warn,fontSize:12,fontFamily:"'Tajawal',sans-serif"}}>
                      🗑️ بيانات
                    </button>
                    <button onClick={()=>setShowDel(u.id)}
                      style={{padding:"9px 12px",borderRadius:10,cursor:"pointer",
                        background:`${C.danger}22`,border:`1px solid ${C.danger}44`,
                        color:C.danger,fontSize:12}}>
                      ❌
                    </button>
                  </div>

                  {/* Delete confirmation */}
                  {showDel===u.id&&(
                    <div style={{marginTop:8,padding:"10px 12px",background:`${C.danger}12`,
                      borderRadius:10,border:`1px solid ${C.danger}44`}}>
                      <div style={{fontSize:12,color:C.danger,marginBottom:8,fontWeight:700}}>
                        ⚠️ حذف "{u.name||u.email}" نهائياً؟ لا يمكن التراجع!
                      </div>
                      <div style={{display:"flex",gap:8}}>
                        <button onClick={()=>deleteUser(u.id)}
                          style={{flex:1,padding:"8px",borderRadius:8,cursor:"pointer",
                            background:C.danger,border:"none",color:"#fff",
                            fontWeight:700,fontSize:12,fontFamily:"'Tajawal',sans-serif"}}>
                          نعم، احذف
                        </button>
                        <button onClick={()=>setShowDel(null)}
                          style={{flex:1,padding:"8px",borderRadius:8,cursor:"pointer",
                            background:C.card2,border:`1px solid ${C.border}`,
                            color:C.muted,fontSize:12}}>
                          إلغاء
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      )}

      {/* ── PENDING PAYMENTS ── */}
      {tab2==="pending"&&(
        <div>
          {pendingPayments.length===0?(
            <div style={{textAlign:"center",padding:40}}>
              <div style={{fontSize:40,marginBottom:8}}>✅</div>
              <div style={{color:C.muted}}>لا توجد دفعات معلقة</div>
            </div>
          ):pendingPayments.map((p,i)=>(
            <div key={i} style={{marginBottom:10,padding:14,borderRadius:14,
              background:`${C.warn}08`,border:`1.5px solid ${C.warn}44`}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}>
                <div style={{fontWeight:700,fontSize:13}}>
                  💳 {(p.gateway||"").toUpperCase()} — {p.plan}
                </div>
                <div style={{fontSize:10,color:C.muted}}>
                  {new Date(p.ts||Date.now()).toLocaleString("ar-SA")}
                </div>
              </div>
              <div style={{fontSize:11,color:C.muted,marginBottom:8,lineHeight:1.7}}>
                المستخدم: <strong style={{color:C.text}}>{p.userEmail||p.userId}</strong><br/>
                المبلغ: <strong style={{color:C.gold}}>${p.amount||0}</strong>
                {p.txId&&<> · المرجع: <span style={{fontFamily:"monospace"}}>{p.txId}</span></>}
              </div>
              {p.proof&&(
                <img src={p.proof} alt="proof"
                  style={{width:"100%",maxHeight:140,objectFit:"contain",
                    borderRadius:8,border:`1px solid ${C.border}`,marginBottom:8}}/>
              )}
              <div style={{display:"flex",gap:8}}>
                <button onClick={()=>approvePlan(p)}
                  style={{flex:2,padding:"10px",borderRadius:10,cursor:"pointer",
                    background:`linear-gradient(135deg,${C.accent3},#059669)`,
                    border:"none",color:"#000",fontWeight:800,fontSize:13,
                    fontFamily:"'Tajawal',sans-serif"}}>
                  ✅ موافقة وتفعيل الخطة
                </button>
                <button onClick={()=>{
                  const newP=pendingPayments.filter((_,j)=>j!==i);
                  DB.set("pending_payments",newP);
                  const log=DB.get("payment_log",[]);
                  DB.set("payment_log",[{...p,approved:false,rejectedAt:Date.now()},...log]);
                  showMsg(false,"❌ تم رفض الدفعة");
                }}
                  style={{flex:1,padding:"10px",borderRadius:10,cursor:"pointer",
                    background:`${C.danger}22`,border:`1px solid ${C.danger}44`,
                    color:C.danger,fontSize:13,fontFamily:"'Tajawal',sans-serif"}}>
                  ❌ رفض
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ── PAYMENT LOG ── */}
      {tab2==="log"&&(
        <div>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:10}}>
            <div style={{fontSize:12,fontWeight:700}}>
              سجل الدفعات ({DB.get("payment_log",[]).length})
            </div>
            <button onClick={()=>{DB.set("payment_log",[]);showMsg(true,"✅ تم مسح السجل");}}
              style={{padding:"4px 10px",borderRadius:8,cursor:"pointer",fontSize:11,
                background:`${C.danger}15`,border:`1px solid ${C.danger}33`,color:C.danger}}>
              مسح السجل
            </button>
          </div>
          {DB.get("payment_log",[]).slice(0,30).map((p,i)=>(
            <div key={i} style={{marginBottom:6,padding:"8px 12px",borderRadius:10,
              background:p.approved?`${C.accent3}08`:`${C.danger}08`,
              border:`1px solid ${p.approved?C.accent3:C.danger}22`,
              display:"flex",justifyContent:"space-between",alignItems:"center",fontSize:11}}>
              <div>
                <div style={{fontWeight:600,color:p.approved?C.accent3:C.danger}}>
                  {p.approved?"✅":"❌"} {p.plan} — {p.gateway}
                </div>
                <div style={{color:C.muted,marginTop:1}}>{p.userEmail}</div>
              </div>
              <div style={{textAlign:"right",color:C.muted}}>
                <div style={{fontWeight:700,color:C.gold}}>${p.amount||0}</div>
                <div style={{fontSize:9}}>
                  {new Date(p.approvedAt||p.rejectedAt||p.ts||Date.now()).toLocaleDateString("ar-SA")}
                </div>
              </div>
            </div>
          ))}
          {DB.get("payment_log",[]).length===0&&(
            <div style={{textAlign:"center",padding:24,color:C.muted}}>لا يوجد سجل بعد</div>
          )}
        </div>
      )}
      </div>
    </div>
  );
}

